Use a character frequency count: two strings are anagrams if, after normalizing case/spaces as needed, both have identical counts for every character.

Example in JavaScript:
```js
function areAnagrams(a, b) {
  const normalize = s => s.toLowerCase().replace(/\s+/g, '');
  a = normalize(a);
  b = normalize(b);
  if (a.length !== b.length) return false;

  const count = new Map();
  for (const ch of a) count.set(ch, (count.get(ch) || 0) + 1);
  for (const ch of b) {
    if (!count.has(ch)) return false;
    const next = count.get(ch) - 1;
    if (next === 0) count.delete(ch);
    else count.set(ch, next);
  }
  return count.size === 0;
}
```

Examples:
- `areAnagrams("listen", "silent")` → `true`
- `areAnagrams("hello", "world")` → `false`

