def length_of_lis(nums):
    tails = []

    for x in nums:
        left, right = 0, len(tails)
        while left < right:
            mid = (left + right) // 2
            if tails[mid] < x:
                left = mid + 1
            else:
                right = mid

        if left == len(tails):
            tails.append(x)
        else:
            tails[left] = x

    return len(tails)
