    { a: 2 }
  );

  // 3. recursively merges nested objects
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: { y: 2 } }),
    { a: { x: 1, y: 2 } }
  );

  // 4. nested primitive conflict prefers b
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: { x: 9 } }),
    { a: { x: 9 } }
  );

  // 5. arrays are overwritten, not merged
  assert.deepStrictEqual(
    deepMerge({ a: [1, 2], keep: true }, { a: [3] }),
    { a: [3], keep: true }
  );

  // 6. null in b overwrites object in a
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: null }),
    { a: null }
  );

  // 7. missing keys are preserved from a
  assert.deepStrictEqual(
    deepMerge({ a: 1, b: 2 }, { b: 3 }),
    { a: 1, b: 3 }
  );

  // 8. empty objects merge correctly
  assert.deepStrictEqual(
    deepMerge({}, {}),
    {}
  );

  // 9. conflicting primitive types prefer b
  assert.deepStrictEqual(
    deepMerge({ a: '1' }, { a: false }),
    { a: false }
  );

  // 10. deep nesting merges recursively
  assert.deepStrictEqual(
    deepMerge(
      { a: { b: { c: { d: 1 } } } },
      { a: { b: { c: { e: 2 } } } }
    ),
    { a: { b: { c: { d: 1, e: 2 } } } }
  );

  // 11. does not mutate either input object
  const left = { a: { x: 1 }, arr: [1, 2] };
  const right = { a: { y: 2 }, arr: [3, 4] };
  const merged = deepMerge(left, right);

  assert.deepStrictEqual(left, { a: { x: 1 }, arr: [1, 2] });
  assert.deepStrictEqual(right, { a: { y: 2 }, arr: [3, 4] });
  assert.notStrictEqual(merged.a, left.a);
  assert.notStrictEqual(merged.arr, right.arr);

  // 12. adding nested object from b clones it
  const source = { a: {} };
  const incoming = { a: { nested: { x: 1 } } };
  const out = deepMerge(source, incoming);
