export function debounce(fn, delay) {
  if (typeof fn !== 'function') {
    throw new TypeError('debounce expected a function');
  }

  let timeoutId = null;

  return function debounced(...args) {
    const context = this;

    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      fn.apply(context, args);
    }, delay);
  };
}
