  if (defaultCountry !== 'US') {
    throw new Error('Only US defaultCountry is supported');
  }

  const extMatch = raw.match(/(?:ext\.?|extension|x)\s*(\d+)\s*$/i);
  const extension = extMatch ? extMatch[1] : null;
  const withoutExtension = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[A-WYZa-wyz]/.test(withoutExtension)) {
    throw new Error('Phone number contains invalid characters');
  }

  const hasPlus = withoutExtension.startsWith('+');
  const plusCount = (withoutExtension.match(/\+/g) || []).length;
  if (plusCount > 1 || (plusCount === 1 && !hasPlus)) {
    throw new Error('Phone number has an invalid + prefix');
  }

  const digits = withoutExtension.replace(/\D/g, '');
  if (digits === '') return null;

  let countryCode;
  let nationalNumber;

  if (hasPlus) {
    if (!digits.startsWith('1') || digits.length !== 11) {
      throw new Error('Only +1 NANP numbers are supported');
    }
    countryCode = '1';
    nationalNumber = digits.slice(1);
  } else if (digits.length === 11 && digits.startsWith('1')) {
    countryCode = '1';
    nationalNumber = digits.slice(1);
  } else if (digits.length === 10) {
    countryCode = '1';
    nationalNumber = digits;
  } else {
    throw new Error('Phone number must contain 10 digits or 11 digits starting with 1');
  }

  if (!/^[2-9]\d{2}[2-9]\d{6}$/.test(nationalNumber)) {
    throw new Error('Phone number is not a valid US/NANP number');
  }

  const formatted = `+${countryCode}${nationalNumber}`;
  return extension ? `${formatted}x${extension}` : formatted;
}

module.exports = { normalizePhoneNumber };
```

