```js
function flattenObject(obj) {
  const result = {};

  function escapeKey(key) {
    return String(key).replaceAll('.', '\\.')
  }

  function visit(value, path) {
    if (value === null || typeof value !== 'object') {
      if (path) result[path] = value;
      return;
    }

    if (Array.isArray(value)) {
      if (!path) {
        value.forEach((item, index) => visit(item, String(index)));
      } else if (value.length === 0) {
        result[path] = [];
      } else {
        value.forEach((item, index) => visit(item, `${path}.${index}`));
      }
      return;
    }

    const entries = Object.entries(value);

    if (entries.length === 0) {
      if (path) result[path] = {};
      return;
    }

    for (const [key, nestedValue] of entries) {
      const nextPath = path ? `${path}.${escapeKey(key)}` : escapeKey(key);
      visit(nestedValue, nextPath);
    }
  }

  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    throw new TypeError('flattenObject expects a non-null plain object');
  }

  visit(obj, '');
  return result;
}
```

