function rotateMatrix(matrix) {
  if (!Array.isArray(matrix)) {
    throw new TypeError('Matrix must be an array');
  }

  const n = matrix.length;

  if (n === 0) {
    return [];
  }

  if (!matrix.every(Array.isArray)) {
    throw new TypeError('Matrix must be a 2D array');
  }

  if (!matrix.every(row => row.length === n)) {
    throw new Error('Matrix must be non-empty and square');
  }

  const rotated = Array.from({ length: n }, () => Array(n));

  for (let row = 0; row < n; row++) {
    for (let col = 0; col < n; col++) {
      rotated[col][n - 1 - row] = matrix[row][col];
    }
  }

  return rotated;
}

module.exports = { rotateMatrix };
```

