```js
function memoize(fn) {
  const root = new Map();

  return function memoized(...args) {
    let node = root;

    for (const arg of args) {
      const isObject = arg !== null && (typeof arg === 'object' || typeof arg === 'function');
      const key = isObject ? arg : `primitive:${typeof arg}:${String(arg)}`;

      if (!node.has(key)) {
        node.set(key, new Map());
      }
      node = node.get(key);
    }

    if (node.has('value')) {
      return node.get('value');
    }

    const result = fn.apply(this, args);
    node.set('value', result);
    return result;
  };
}

module.exports = { memoize };
```

