const assert = require('assert');
const { memoize } = require('./memoize');

describe('memoize', () => {
  it('caches primitive arguments', () => {
    let calls = 0;
    const fn = memoize((a, b) => {
      calls += 1;
      return a + b;
    });

    assert.strictEqual(fn(1, 2), 3);
    assert.strictEqual(fn(1, 2), 3);
    assert.strictEqual(calls, 1);
  });

  it('distinguishes different primitive values', () => {
    let calls = 0;
    const fn = memoize((a) => {
      calls += 1;
      return a;
    });

    fn(1);
    fn('1');
    fn(true);
    assert.strictEqual(calls, 3);
  });

  it('caches object arguments by reference', () => {
    let calls = 0;
    const fn = memoize((obj) => {
      calls += 1;
      return obj.value * 2;
    });

    const obj = { value: 4 };
    assert.strictEqual(fn(obj), 8);
    assert.strictEqual(fn(obj), 8);
    assert.strictEqual(calls, 1);
  });

  it('treats different object references as different keys', () => {
    let calls = 0;
    const fn = memoize((obj) => {
      calls += 1;
      return obj.value;
    });

    assert.strictEqual(fn({ value: 1 }), 1);
    assert.strictEqual(fn({ value: 1 }), 1);
    assert.strictEqual(calls, 2);
  });

  it('respects argument order', () => {
    let calls = 0;
    const fn = memoize((a, b) => {
      calls += 1;
      return `${a}-${b}`;
    });

    assert.strictEqual(fn('x', 'y'), 'x-y');
    assert.strictEqual(fn('y', 'x'), 'y-x');
    assert.strictEqual(fn('x', 'y'), 'x-y');
    assert.strictEqual(calls, 2);
  });

  it('caches undefined results', () => {
    let calls = 0;
    const fn = memoize((x) => {
      calls += 1;
      if (x > 0) return undefined;
      return 'nope';
    });

    assert.strictEqual(fn(1), undefined);
    assert.strictEqual(fn(1), undefined);
    assert.strictEqual(calls, 1);
  });

  it('does not cache thrown errors', () => {
    let calls = 0;
    const fn = memoize((x) => {
      calls += 1;
      if (x === 1) throw new Error('boom');
      return x;
    });

    assert.throws(() => fn(1), /boom/);
    assert.throws(() => fn(1), /boom/);
    assert.strictEqual(calls, 2);
  });

  it('preserves this context', () => {
    let calls = 0;
    const obj = {
      factor: 3,
      calc: memoize(function (n) {
        calls += 1;
        return n * this.factor;
      }),
    };

    assert.strictEqual(obj.calc(2), 6);
    assert.strictEqual(obj.calc(2), 6);
    assert.strictEqual(calls, 1);
  });

  it('supports zero-argument functions', () => {
    let calls = 0;
    const fn = memoize(() => {
      calls += 1;
      return 42;
    });

    assert.strictEqual(fn(), 42);
    assert.strictEqual(fn(), 42);
    assert.strictEqual(calls, 1);
  });
});
```

**Cache key strategy**
- Primitive arguments are keyed by a tagged string: `primitive:<type>:<value>`.
- Object and function arguments are keyed by reference identity.
- Arguments are stored in a nested `Map` trie, so order matters naturally.
- Results are stored only after successful execution, so thrown errors are not cached.
- `undefined` is cached correctly by checking key presence with `has('value')` instead of comparing the stored value.

