function diffArrays(a, b) {
  if (!Array.isArray(a) || !Array.isArray(b)) {
    throw new TypeError('diffArrays expects two arrays');
  }

  const countsA = new Map();
  const countsB = new Map();

  for (const item of a) countsA.set(item, (countsA.get(item) || 0) + 1);
  for (const item of b) countsB.set(item, (countsB.get(item) || 0) + 1);

  const keys = new Set([...countsA.keys(), ...countsB.keys()]);
  const added = [];
  const removed = [];
  const unchanged = [];

  for (const key of keys) {
    const countA = countsA.get(key) || 0;
    const countB = countsB.get(key) || 0;
    const shared = Math.min(countA, countB);

    for (let i = 0; i < shared; i++) unchanged.push(key);
    for (let i = 0; i < countB - shared; i++) added.push(key);
    for (let i = 0; i < countA - shared; i++) removed.push(key);
  }

  return { added, removed, unchanged };
}

module.exports = { diffArrays };
```

Multiplicity **does matter**: duplicates are counted, so if `a = [1, 1]` and `b = [1]`, one `1` is `unchanged` and one `1` is `removed`.

