function slugify(input) {
  const transliterationMap = new Map([
    ['ß', 'ss'], ['ẞ', 'ss'],
    ['Æ', 'ae'], ['æ', 'ae'],
    ['Œ', 'oe'], ['œ', 'oe'],
    ['Ø', 'o'], ['ø', 'o'],
    ['Ð', 'd'], ['ð', 'd'],
    ['Þ', 'th'], ['þ', 'th'],
    ['Ł', 'l'], ['ł', 'l'],
    ['Đ', 'd'], ['đ', 'd'],
    ['Ħ', 'h'], ['ħ', 'h'],
    ['ı', 'i'],
    ['ĸ', 'k'],
    ['Ŋ', 'n'], ['ŋ', 'n']
  ]);

  if (input == null) return '';

  let text = String(input).trim();
  if (!text) return '';

  text = Array.from(text, (char) => transliterationMap.get(char) ?? char).join('');

  text = text
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/['’]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-+/g, '-');

  return text;
}

module.exports = { slugify };
```

