function compareVersions(a, b) {
  const parse = (input) => {
    if (typeof input !== "string" || input.trim() === "") {
      throw new TypeError("Version must be a non-empty string");
    }

    const value = input.trim();

    if (!/^\d+(?:\.\d+)*$/.test(value)) {
      throw new TypeError(`Invalid version format: ${input}`);
    }

    const parts = value.split(".").map((part) => {
      if (!/^\d+$/.test(part)) {
        throw new TypeError(`Invalid numeric segment: ${part}`);
      }
      return Number(part);
    });

    return parts;
  };

  const left = parse(a);
  const right = parse(b);
  const maxLen = Math.max(left.length, right.length);

  for (let i = 0; i < maxLen; i++) {
    const x = left[i] ?? 0;
    const y = right[i] ?? 0;

    if (x > y) return 1;
    if (x < y) return -1;
  }

  return 0;
}
```

