function intersectIntervals(intervals) {
  if (!Array.isArray(intervals)) {
    throw new TypeError('intervals must be an array');
  }

  if (intervals.length === 0) {
    return null;
  }

  let maxStart = -Infinity;
  let minEnd = Infinity;

  for (const interval of intervals) {
    if (!Array.isArray(interval) || interval.length !== 2) {
      throw new TypeError('each interval must be a two-element array');
    }

    const [rawA, rawB] = interval;

    if (!Number.isFinite(rawA) || !Number.isFinite(rawB)) {
      throw new TypeError('interval endpoints must be finite numbers');
    }

    const start = Math.min(rawA, rawB);
    const end = Math.max(rawA, rawB);

    maxStart = Math.max(maxStart, start);
    minEnd = Math.min(minEnd, end);

    if (maxStart > minEnd) {
      return null;
    }
  }

  return [maxStart, minEnd];
}

module.exports = { intersectIntervals };
```

