```js
function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new TypeError('maxWidth must be a positive integer');
  }
  if (typeof text !== 'string') {
    throw new TypeError('text must be a string');
  }
  if (text === '') {
    return '';
  }

  const lines = text.split('\n');
  const wrapped = lines.map(wrapLine);
  return wrapped.join('\n');

  function wrapLine(line) {
    if (line === '') {
      return '';
    }

    const tokens = line.match(/\S+|\s+/g) || [];
    const out = [];
    let current = '';

    for (const token of tokens) {
      if (/^\s+$/.test(token)) {
        if (current !== '') {
          current += token;
        }
        continue;
      }

      if (current === '') {
        pushLongWord(token);
        continue;
      }

      if ((current + token).length <= maxWidth) {
        current += token;
        continue;
      }

      out.push(trimRight(current));
      current = '';
      pushLongWord(token);
    }

    if (current !== '') {
      out.push(trimRight(current));
    }

    return out.join('\n');

    function pushLongWord(word) {
      if (word.length <= maxWidth) {
        current = word;
        return;
      }

      let i = 0;
      while (i < word.length) {
        const chunk = word.slice(i, i + maxWidth);
        if (chunk.length === maxWidth) {
          out.push(chunk);
        } else {
          current = chunk;
        }
        i += maxWidth;
      }
    }
  }

  function trimRight(value) {
    return value.replace(/[ \t]+$/g, '');
  }
}

module.exports = { wordWrap };
```

