```js
function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const roots = [];
  const parentById = new Map();

  for (const item of items) {
    if (!item || typeof item !== 'object') {
      throw new TypeError('each item must be an object');
    }

    const { id, parentId = null } = item;

    if (id === null || id === undefined) {
      throw new Error('item id is required');
    }

    if (nodes.has(id)) {
      throw new Error(`duplicate id: ${id}`);
    }

    nodes.set(id, { ...item, parentId, children: [] });
    parentById.set(id, parentId);
  }

  for (const [id, node] of nodes) {
    const parentId = node.parentId;

    if (parentId === null || parentId === undefined) {
      roots.push(node);
      continue;
    }

    if (parentId === id) {
      throw new Error(`cycle detected: ${id} cannot be its own parent`);
    }

    const parent = nodes.get(parentId);
    if (!parent) {
      roots.push(node);
      continue;
    }

    parent.children.push(node);
  }

  const state = new Map();

  function visit(node, path) {
    const current = state.get(node.id) || 0;
    if (current === 1) {
      throw new Error(`cycle detected: ${[...path, node.id].join(' -> ')}`);
    }
    if (current === 2) {
      return;
    }

    state.set(node.id, 1);
    for (const child of node.children) {
      visit(child, [...path, node.id]);
    }
    state.set(node.id, 2);
  }

  for (const root of roots) {
    visit(root, []);
  }

  if (state.size !== nodes.size) {
    const unvisited = [...nodes.keys()].filter(id => !state.has(id));
    throw new Error(`cycle detected involving: ${unvisited.join(', ')}`);
  }

  return roots;
}

module.exports = { buildTree };
```

