function relativePath(from, to) {
  if (typeof from !== 'string' || typeof to !== 'string') {
    throw new TypeError('Paths must be strings');
  }

  const normalize = (input) => {
    const path = input.replace(/\\/g, '/');
    const isAbsolute = path.startsWith('/');
    if (!isAbsolute) {
      throw new Error('Paths must be absolute');
    }

    const parts = path.split('/');
    const normalized = [];

    for (const part of parts) {
      if (!part || part === '.') continue;
      if (part === '..') {
        if (normalized.length > 0) normalized.pop();
        continue;
      }
      normalized.push(part);
    }

    return normalized;
  };

  const fromParts = normalize(from);
  const toParts = normalize(to);

  let i = 0;
  while (i < fromParts.length && i < toParts.length && fromParts[i] === toParts[i]) {
    i++;
  }

  const up = new Array(fromParts.length - i).fill('..');
  const down = toParts.slice(i);
  const result = [...up, ...down].join('/');

  return result || '.';
}

module.exports = { relativePath };
```

