```js
/**
 * Sort an array of objects by multiple keys and directions.
 *
 * Assumptions:
 * - `items` must be an array.
 * - `rules` must be an array of objects like `{ key, direction }`.
 * - `direction` may be `"asc"` or `"desc"` and defaults to `"asc"`.
 * - Missing values (`undefined` or `null`) sort after present values in ascending
 *   order and before present values in descending order.
 * - When values have different primitive types, they are compared by a fixed type
 *   precedence to keep ordering deterministic:
 *   number < bigint < string < boolean < symbol < object.
 * - If all rules consider two items equal, the original input order is preserved
 *   (stable sort).
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }

  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const normalizedRules = rules.map((rule, index) => {
    if (!rule || typeof rule !== 'object' || Array.isArray(rule)) {
      throw new TypeError(`rules[${index}] must be an object`);
    }

    const { key, direction = 'asc' } = rule;

    if (typeof key !== 'string' || key.length === 0) {
      throw new TypeError(`rules[${index}].key must be a non-empty string`);
    }

    if (direction !== 'asc' && direction !== 'desc') {
      throw new TypeError(`rules[${index}].direction must be "asc" or "desc"`);
    }

    return { key, direction };
  });

  const decorated = items.map((item, index) => ({ item, index }));

  decorated.sort((a, b) => {
    for (const { key, direction } of normalizedRules) {
      const result = compareValues(a.item?.[key], b.item?.[key]);
      if (result !== 0) {
        return direction === 'desc' ? -result : result;
      }
    }

    return a.index - b.index;
  });

  return decorated.map(entry => entry.item);
}

function compareValues(a, b) {
  const aMissing = a == null;
  const bMissing = b == null;

  if (aMissing && bMissing) return 0;
  if (aMissing) return 1;
  if (bMissing) return -1;

  const typeOrder = {
    number: 0,
    bigint: 1,
    string: 2,
    boolean: 3,
    symbol: 4,
    object: 5,
    function: 6,
    undefined: 7,
  };

  const typeA = typeof a;
  const typeB = typeof b;

  if (typeA !== typeB) {
    return (typeOrder[typeA] ?? 99) - (typeOrder[typeB] ?? 99);
  }

  if (typeA === 'number') {
    const aNaN = Number.isNaN(a);
    const bNaN = Number.isNaN(b);
    if (aNaN && bNaN) return 0;
    if (aNaN) return 1;
    if (bNaN) return -1;
  }

  if (a < b) return -1;
  if (a > b) return 1;
  return 0;
}

module.exports = { sortByMultiple };
```

