```js
function minWindowSubstring(text, pattern) {
  if (pattern.length === 0) return "";
  if (text.length === 0 || pattern.length > text.length) return "";

  const need = new Map();
  for (const char of pattern) {
    need.set(char, (need.get(char) || 0) + 1);
  }

  let missing = pattern.length;
  let left = 0;
  let bestStart = 0;
  let bestLength = Infinity;

  for (let right = 0; right < text.length; right++) {
    const char = text[right];

    if (need.has(char)) {
      const count = need.get(char);
      if (count > 0) missing--;
      need.set(char, count - 1);
    }

    while (missing === 0) {
      const windowLength = right - left + 1;
      if (windowLength < bestLength) {
        bestLength = windowLength;
        bestStart = left;
      }

      const leftChar = text[left];
      if (need.has(leftChar)) {
        const count = need.get(leftChar) + 1;
        need.set(leftChar, count);
        if (count > 0) missing++;
      }
      left++;
    }
  }

  return bestLength === Infinity
    ? ""
    : text.slice(bestStart, bestStart + bestLength);
}

module.exports = { minWindowSubstring };
```

