```js
class ListNode {
  constructor(val) {
    this.val = val;
    this.next = null;
  }
}

function buildList(values) {
  if (values.length === 0) return null;

  const nodes = values.map((v) => new ListNode(v));
  for (let i = 0; i < nodes.length - 1; i++) {
    nodes[i].next = nodes[i + 1];
  }
  return { head: nodes[0], nodes };
}

function detectCycle(head) {
  let slow = head;
  let fast = head;

  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;

    if (slow === fast) return true;
  }

  return false;
}

function runTests() {
  const tests = [];

  // 1. empty list
  tests.push({
    name: 'empty list',
    head: null,
    expected: false,
  });

  // 2. one node without cycle
  {
    const node = new ListNode(1);
    tests.push({
      name: 'one node without cycle',
      head: node,
      expected: false,
    });
  }

  // 3. one node with self-cycle
  {
    const node = new ListNode(1);
    node.next = node;
    tests.push({
      name: 'one node with self-cycle',
      head: node,
      expected: true,
    });
  }

  // 4. multiple nodes without cycle
  {
    const { head } = buildList([1, 2, 3, 4]);
    tests.push({
      name: 'no cycle',
      head,
      expected: false,
    });
  }

  // 5. cycle back to head
  {
    const { head, nodes } = buildList([1, 2, 3, 4]);
    nodes[3].next = head;
    tests.push({
      name: 'cycle to head',
      head,
      expected: true,
    });
  }

  // 6. cycle in the middle
  {
    const { head, nodes } = buildList([1, 2, 3, 4, 5]);
    nodes[4].next = nodes[2];
    tests.push({
      name: 'cycle in middle',
      head,
      expected: true,
    });
  }

  // 7. two nodes without cycle
  {
    const { head } = buildList([1, 2]);
    tests.push({
      name: 'two nodes without cycle',
      head,
      expected: false,
    });
  }

  for (const { name, head, expected } of tests) {
    const actual = detectCycle(head);
    if (actual !== expected) {
      throw new Error(`${name}: expected ${expected}, got ${actual}`);
    }
    console.log(`PASS: ${name}`);
  }
}

runTests();
```

This uses Floyd’s tortoise-and-hare algorithm, runs in `O(n)` time, uses `O(1)` extra space, and does not modify the list.

