  const mode = highestFrequency === 1 || modes.length === frequencies.size
    ? null
    : modes.length === 1
      ? modes[0]
      : modes;

  return {
    count,
    min,
    max,
    mean,
    median,
    mode,
    range: max - min,
  };
}
