function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('n must be a non-empty string of digits');
  }
  if (n === '0') {
    throw new RangeError('n must represent a positive integer');
  }

  const len = n.length;
  const prefixLen = Math.ceil(len / 2);
  const prefix = BigInt(n.slice(0, prefixLen));
  const original = BigInt(n);

  const makePalindrome = (half) => {
    const s = half.toString();
    const left = s;
    const right = len % 2 === 0 ? s.split('').reverse().join('') : s.slice(0, -1).split('').reverse().join('');
    return BigInt(left + right);
  };

  const candidates = new Set();
  candidates.add((10n ** BigInt(len - 1)) - 1n);
  candidates.add((10n ** BigInt(len)) + 1n);

  for (const delta of [-1n, 0n, 1n]) {
    const half = prefix + delta;
    if (half > 0n) {
      candidates.add(makePalindrome(half));
    }
  }

  let best = null;

  for (const candidate of candidates) {
    if (candidate === original) continue;

    const diff = candidate > original ? candidate - original : original - candidate;
    if (
      best === null ||
      diff < best.diff ||
      (diff === best.diff && candidate < best.value)
    ) {
      best = { value: candidate, diff };
    }
  }

  return best.value.toString();
}

// Tests
const assert = require('assert');

assert.strictEqual(nearestPalindrome('1'), '0');
assert.strictEqual(nearestPalindrome('8'), '7');
assert.strictEqual(nearestPalindrome('10'), '9');
assert.strictEqual(nearestPalindrome('11'), '9');
assert.strictEqual(nearestPalindrome('99'), '101');
assert.strictEqual(nearestPalindrome('100'), '99');
assert.strictEqual(nearestPalindrome('121'), '111');
assert.strictEqual(nearestPalindrome('123'), '121');
assert.strictEqual(nearestPalindrome('1000'), '999');
assert.strictEqual(nearestPalindrome('1283'), '1331');
assert.strictEqual(nearestPalindrome('999999999999999999'), '1000000000000000001');
assert.strictEqual(nearestPalindrome('1000000000000000000'), '999999999999999999');

assert.throws(() => nearestPalindrome(''), /non-empty string of digits/);
assert.throws(() => nearestPalindrome('0012'), /positive integer|digits/);
assert.throws(() => nearestPalindrome('12a'), /digits/);
assert.throws(() => nearestPalindrome(121), /digits/);
assert.throws(() => nearestPalindrome('0'), /positive integer/);

console.log('All tests passed');
