        while (i < code.length && code[i] !== '\n') i++;
        continue;
      }

      if (ch === '/' && next === '*') {
        i += 2;
        while (i < code.length && !(code[i] === '*' && code[i + 1] === '/')) i++;
        if (i < code.length) i += 2;
        continue;
      }

      if (ch === '"' || ch === "'" || ch === '`') {
        state = 'string';
        quote = ch;
        out += ch;
        i++;
        continue;
      }

      out += ch;
      i++;
      continue;
    }

    if (state === 'string') {
      out += ch;

      if (ch === '\\') {
        if (i + 1 < code.length) {
          out += code[i + 1];
          i += 2;
        } else {
          i++;
        }
        continue;
      }

      if (ch === quote) {
        state = 'code';
        quote = '';
      }

      i++;
    }
  }

  return out;
}

module.exports = { removeComments };
