  if (index < 0 || index >= nums.length) return false;

  const left = index === 0 ? -Infinity : nums[index - 1];
  const right = index === nums.length - 1 ? -Infinity : nums[index + 1];
  return nums[index] >= left && nums[index] >= right;
}

