function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (!s) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const roman = s.toUpperCase();
  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };
  const subtractives = {
    I: new Set(['V', 'X']),
    X: new Set(['L', 'C']),
    C: new Set(['D', 'M']),
  };
  const nonRepeatable = new Set(['V', 'L', 'D']);

  let total = 0;
  let repeatCount = 1;

  for (let i = 0; i < roman.length; i++) {
    const curr = roman[i];
    const next = roman[i + 1];
    const currValue = values[curr];
    const nextValue = next ? values[next] : 0;

    if (i > 0) {
      if (roman[i - 1] === curr) {
        repeatCount += 1;
      } else {
        repeatCount = 1;
      }

      if (nonRepeatable.has(curr) && repeatCount > 1) {
        throw new Error(`Invalid Roman numeral: ${curr} cannot repeat`);
      }
      if (repeatCount > 3) {
        throw new Error(`Invalid Roman numeral: ${curr} repeated too many times`);
      }
    }

    if (next && currValue < nextValue) {
      if (!subtractives[curr] || !subtractives[curr].has(next)) {
        throw new Error(`Invalid Roman numeral: ${curr}${next} is not a valid subtractive pair`);
      }
      if (repeatCount > 1) {
        throw new Error(`Invalid Roman numeral: repeated symbol before subtractive pair`);
      }
      if (i > 0 && values[roman[i - 1]] < currValue) {
        throw new Error('Invalid Roman numeral: malformed subtractive sequence');
      }

      total += nextValue - currValue;
      i += 1;
      repeatCount = 1;
    } else {
      total += currValue;
    }
  }

  const canonical = intToRoman(total);
  if (canonical !== roman) {
    throw new Error('Invalid Roman numeral: malformed or non-canonical numeral');
  }

  return total;
}

function intToRoman(num) {
  const pairs = [
    [1000, 'M'],
    [900, 'CM'],
    [500, 'D'],
    [400, 'CD'],
    [100, 'C'],
    [90, 'XC'],
    [50, 'L'],
    [40, 'XL'],
    [10, 'X'],
    [9, 'IX'],
    [5, 'V'],
    [4, 'IV'],
    [1, 'I'],
  ];

  let result = '';
  for (const [value, symbol] of pairs) {
    while (num >= value) {
      result += symbol;
      num -= value;
    }
  }
  return result;
}
```

