function knapsack01(items, capacity) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Number.isInteger(capacity) || capacity < 0) {
    throw new TypeError('capacity must be a non-negative integer');
  }

  const zeroWeightValue = { sum: 0 };
  const normalized = items.map((item, index) => {
    if (item === null || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${index}] must be an object`);
    }

    const { weight, value } = item;

    if (!Number.isInteger(weight) || weight < 0) {
      throw new TypeError(`items[${index}].weight must be a non-negative integer`);
    }

    if (typeof value !== 'number' || !Number.isFinite(value)) {
      throw new TypeError(`items[${index}].value must be a finite number`);
    }

    if (weight === 0) {
      if (value > 0) zeroWeightValue.sum += value;
      return null;
    }

    return { weight, value };
  }).filter(Boolean);

  const dp = Array(capacity + 1).fill(0);

  for (const { weight, value } of normalized) {
    for (let c = capacity; c >= weight; c--) {
      dp[c] = Math.max(dp[c], dp[c - weight] + value);
    }
  }

  return dp[capacity] + zeroWeightValue.sum;
}

module.exports = { knapsack01 };
```

