function longestCommonPrefix(words) {
  if (!Array.isArray(words) || words.length === 0) return '';
  if (words.length === 1) return String(words[0] ?? '');

  const normalized = words.map(word => String(word ?? ''));
  let prefix = normalized[0];

  for (let i = 1; i < normalized.length && prefix !== ''; i++) {
    const current = normalized[i];
    let j = 0;
    const max = Math.min(prefix.length, current.length);

    while (j < max && prefix[j] === current[j]) j++;
    prefix = prefix.slice(0, j);
  }

  return prefix;
}

module.exports = { longestCommonPrefix };
