function balancedBrackets(input) {
  const pairs = {
    ')': '(',
    ']': '[',
    '}': '{',
  };
  const openings = new Set(['(', '[', '{']);
  const stack = [];

  for (const char of String(input)) {
    if (openings.has(char)) {
      stack.push(char);
      continue;
    }

    if (char in pairs) {
      if (stack.pop() !== pairs[char]) {
        return false;
      }
    }
  }

  return stack.length === 0;
}

module.exports = { balancedBrackets };
```

