```ts
import crypto from 'node:crypto';
import express from 'express';

type Provider = 'stripe' | 'github' | 'slack';

type VerifyInput = {
  provider: Provider;
  headers: Record<string, string | undefined>;
  rawBody: Buffer;
  secret: string;
  toleranceSeconds?: number;
};

type VerifyResult =
  | { ok: true; provider: Provider; metadata?: Record<string, string | number> }
  | { ok: false; provider: Provider; reason: string };

const app = express();

app.use(
  express.json({
    verify: (req, _res, buf) => {
      (req as any).rawBody = Buffer.from(buf);
    },
  }),
);

function timingSafeEqual(a: string, b: string) {
  const ab = Buffer.from(a);
  const bb = Buffer.from(b);
  if (ab.length !== bb.length) return false;
  return crypto.timingSafeEqual(ab, bb);
}

function hmacSHA256(secret: string, payload: Buffer | string) {
  return crypto.createHmac('sha256', secret).update(payload).digest('hex');
}

function verifyStripe({ headers, rawBody, secret, toleranceSeconds = 300 }: VerifyInput): VerifyResult {
  const sig = headers['stripe-signature'];
  if (!sig) return { ok: false, provider: 'stripe', reason: 'Missing stripe-signature header' };

  const parts = Object.fromEntries(
    sig.split(',').map((part) => {
      const [k, v] = part.split('=');
      return [k, v];
    }),
  );

  const timestamp = Number(parts.t);
  const signature = parts.v1;
  if (!timestamp || !signature) {
    return { ok: false, provider: 'stripe', reason: 'Invalid stripe-signature format' };
  }

  const age = Math.abs(Math.floor(Date.now() / 1000) - timestamp);
  if (age > toleranceSeconds) {
    return { ok: false, provider: 'stripe', reason: 'Signature timestamp outside tolerance' };
  }

  const signedPayload = `${timestamp}.${rawBody.toString('utf8')}`;
  const expected = hmacSHA256(secret, signedPayload);

  if (!timingSafeEqual(expected, signature)) {
    return { ok: false, provider: 'stripe', reason: 'Signature mismatch' };
  }

  return { ok: true, provider: 'stripe', metadata: { timestamp } };
}

function verifyGitHub({ headers, rawBody, secret }: VerifyInput): VerifyResult {
  const sig = headers['x-hub-signature-256'];
  if (!sig) return { ok: false, provider: 'github', reason: 'Missing x-hub-signature-256 header' };
  if (!sig.startsWith('sha256=')) {
    return { ok: false, provider: 'github', reason: 'Invalid GitHub signature format' };
  }

  const expected = `sha256=${hmacSHA256(secret, rawBody)}`;
  if (!timingSafeEqual(expected, sig)) {
    return { ok: false, provider: 'github', reason: 'Signature mismatch' };
  }

  return { ok: true, provider: 'github' };
}

function verifySlack({ headers, rawBody, secret, toleranceSeconds = 300 }: VerifyInput): VerifyResult {
  const ts = headers['x-slack-request-timestamp'];
  const sig = headers['x-slack-signature'];

  if (!ts || !sig) {
    return { ok: false, provider: 'slack', reason: 'Missing Slack signature headers' };
  }

  const timestamp = Number(ts);
  if (!timestamp) {
    return { ok: false, provider: 'slack', reason: 'Invalid Slack timestamp' };
  }

  const age = Math.abs(Math.floor(Date.now() / 1000) - timestamp);
  if (age > toleranceSeconds) {
    return { ok: false, provider: 'slack', reason: 'Signature timestamp outside tolerance' };
  }

  const base = `v0:${timestamp}:${rawBody.toString('utf8')}`;
  const expected = `v0=${hmacSHA256(secret, base)}`;

  if (!timingSafeEqual(expected, sig)) {
    return { ok: false, provider: 'slack', reason: 'Signature mismatch' };
  }

  return { ok: true, provider: 'slack', metadata: { timestamp } };
}

export function verifyWebhookSignature(input: VerifyInput): VerifyResult {
  switch (input.provider) {
    case 'stripe':
      return verifyStripe(input);
    case 'github':
      return verifyGitHub(input);
    case 'slack':
      return verifySlack(input);
    default:
      return { ok: false, provider: input.provider, reason: 'Unsupported provider' } as never;
  }
}

app.post('/webhooks/:provider', (req, res) => {
  const provider = req.params.provider as Provider;
  const secret = process.env[`WEBHOOK_SECRET_${provider.toUpperCase()}`];

  if (!secret) {
    return res.status(500).json({ error: 'Webhook secret not configured' });
  }

  const headers = Object.fromEntries(
    Object.entries(req.headers).map(([k, v]) => [k.toLowerCase(), Array.isArray(v) ? v[0] : v]),
  );

  const result = verifyWebhookSignature({
    provider,
    headers,
    rawBody: (req as any).rawBody,
    secret,
  });

  if (!result.ok) {
    return res.status(401).json({ error: result.reason });
  }

  return res.status(202).json({ verified: true, provider: result.provider, metadata: result.metadata });
});

app.listen(3000);
```

### Service design
- Accept the **raw request body** before JSON parsing changes bytes.
- Normalize headers to lowercase.
- Verify with **provider-specific canonical string rules**.
- Use **constant-time comparison** for signatures.
- Enforce **timestamp tolerance** for replay protection where supported.
- Return `401` for failed verification and only process the event after verification succeeds.

### Recommended architecture
- `VerifierRegistry`: maps provider name to verifier.
- `ProviderVerifier` interface: `verify(headers, rawBody, secret) => result`.
- `ReplayProtection`: optional store keyed by delivery ID or signature+timestamp.
- `SecretResolver`: loads current secret, optionally supports secret rotation.
- `AuditLogger`: logs provider, event ID, verification outcome, and failure reason without logging secrets.

### Hardening
- Limit body size.
- Reject unsupported providers early.
- Support secret rotation by checking active then previous secret.
- Store and reject duplicate delivery IDs for providers like GitHub/Stripe.
- Keep webhook verification separate from business logic.
- Do not parse or trust the JSON payload until verification passes.

### Minimal tests
- Valid signature passes for each provider.
- Wrong secret fails.
- Modified body fails.
- Expired timestamp fails for Stripe/Slack.
- Missing headers fail.
- Rotated old secret still passes if configured.

If you want, I can also turn this into a full design doc with API contract, sequence diagram, threat model, and production deployment notes.

697.answer:
```ts
// shopping-cart-service.ts

type CartStatus = 'ACTIVE' | 'CHECKED_OUT' | 'ABANDONED';

type CartItem = {
  productId: string;
  sku?: string;
  quantity: number;
  unitPrice: number;
  currency: string;
  title?: string;
  metadata?: Record<string, string>;
};

type Cart = {
  id: string;
  userId?: string;
  sessionId?: string;
  status: CartStatus;
  items: CartItem[];
  couponCodes: string[];
  subtotal: number;
  discountTotal: number;
  taxTotal: number;
  shippingTotal: number;
  grandTotal: number;
  currency: string;
  version: number;
  createdAt: Date;
  updatedAt: Date;
  expiresAt?: Date;
};

type AddItemInput = {
  cartId?: string;
  userId?: string;
  sessionId?: string;
  productId: string;
  sku?: string;
  quantity: number;
};

type UpdateItemInput = {
  cartId: string;
  productId: string;
  sku?: string;
  quantity: number;
};

interface ProductCatalog {
  getSellableItem(productId: string, sku?: string): Promise<{
    productId: string;
    sku?: string;
    title: string;
    unitPrice: number;
    currency: string;
    isAvailable: boolean;
  }>;
}

interface PromotionService {
  calculateDiscount(cart: Cart): Promise<number>;
}

interface TaxService {
  calculateTax(cart: Cart): Promise<number>;
}

interface CartRepository {
  findById(cartId: string): Promise<Cart | null>;
  findActiveByUserId(userId: string): Promise<Cart | null>;
  findActiveBySessionId(sessionId: string): Promise<Cart | null>;
  save(cart: Cart): Promise<void>;
  delete(cartId: string): Promise<void>;
}

class ShoppingCartService {
  constructor(
    private readonly repo: CartRepository,
    private readonly catalog: ProductCatalog,
    private readonly promotions: PromotionService,
    private readonly taxes: TaxService,
  ) {}

  async getOrCreateCart(params: {
    cartId?: string;
    userId?: string;
    sessionId?: string;
  }): Promise<Cart> {
    const existing = await this.findCart(params);
    if (existing) return existing;

    const cart: Cart = {
      id: crypto.randomUUID(),
      userId: params.userId,
      sessionId: params.sessionId,
      status: 'ACTIVE',
      items: [],
      couponCodes: [],
      subtotal: 0,
      discountTotal: 0,
      taxTotal: 0,
      shippingTotal: 0,
      grandTotal: 0,
      currency: 'USD',
      version: 1,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    await this.repo.save(cart);
    return cart;
  }

  async addItem(input: AddItemInput): Promise<Cart> {
    if (input.quantity <= 0) {
      throw new Error('quantity must be greater than 0');
    }

    const cart = await this.getOrCreateCart(input);
    this.ensureMutable(cart);

    const sellable = await this.catalog.getSellableItem(input.productId, input.sku);
    if (!sellable.isAvailable) {
      throw new Error('item is not available');
    }

    const existingItem = cart.items.find(
      (item) => item.productId === input.productId && item.sku === input.sku,
    );

    if (existingItem) {
      existingItem.quantity += input.quantity;
      existingItem.unitPrice = sellable.unitPrice;
    } else {
      cart.items.push({
        productId: sellable.productId,
        sku: sellable.sku,
        quantity: input.quantity,
        unitPrice: sellable.unitPrice,
        currency: sellable.currency,
        title: sellable.title,
      });
    }

    return this.recalculateAndSave(cart);
  }

  async updateItem(input: UpdateItemInput): Promise<Cart> {
    const cart = await this.requireCart(input.cartId);
    this.ensureMutable(cart);

    const item = cart.items.find(
      (entry) => entry.productId === input.productId && entry.sku === input.sku,
    );

    if (!item) {
      throw new Error('item not found');
    }

    if (input.quantity <= 0) {
      cart.items = cart.items.filter(
        (entry) => !(entry.productId === input.productId && entry.sku === input.sku),
      );
    } else {
      item.quantity = input.quantity;
    }

    return this.recalculateAndSave(cart);
  }

  async applyCoupon(cartId: string, couponCode: string): Promise<Cart> {
    const cart = await this.requireCart(cartId);
    this.ensureMutable(cart);

    if (!cart.couponCodes.includes(couponCode)) {
      cart.couponCodes.push(couponCode);
    }

    return this.recalculateAndSave(cart);
  }

  async mergeGuestCart(sessionId: string, userId: string): Promise<Cart> {
    const guestCart = await this.repo.findActiveBySessionId(sessionId);
    const userCart = await this.repo.findActiveByUserId(userId);

    if (!guestCart && !userCart) {
      return this.getOrCreateCart({ userId, sessionId });
    }
    if (!guestCart) return userCart!;
    if (!userCart) {
      guestCart.userId = userId;
      guestCart.sessionId = undefined;
      return this.recalculateAndSave(guestCart);
    }

    for (const guestItem of guestCart.items) {
      const match = userCart.items.find(
        (item) => item.productId === guestItem.productId && item.sku === guestItem.sku,
      );

      if (match) match.quantity += guestItem.quantity;
      else userCart.items.push(guestItem);
    }

    userCart.couponCodes = [...new Set([...userCart.couponCodes, ...guestCart.couponCodes])];
    await this.repo.delete(guestCart.id);
    return this.recalculateAndSave(userCart);
  }

  async checkout(cartId: string): Promise<Cart> {
    const cart = await this.requireCart(cartId);
    this.ensureMutable(cart);

    if (cart.items.length === 0) {
      throw new Error('cannot checkout an empty cart');
    }

    cart.status = 'CHECKED_OUT';
    cart.updatedAt = new Date();
    cart.version += 1;
    await this.repo.save(cart);
    return cart;
  }

  private async findCart(params: {
    cartId?: string;
    userId?: string;
    sessionId?: string;
  }): Promise<Cart | null> {
    if (params.cartId) return this.repo.findById(params.cartId);
    if (params.userId) return this.repo.findActiveByUserId(params.userId);
    if (params.sessionId) return this.repo.findActiveBySessionId(params.sessionId);
    return null;
  }

  private async requireCart(cartId: string): Promise<Cart> {
    const cart = await this.repo.findById(cartId);
    if (!cart) throw new Error('cart not found');
    return cart;
  }

  private ensureMutable(cart: Cart): void {
    if (cart.status !== 'ACTIVE') {
      throw new Error('cart is not editable');
    }
  }

  private async recalculateAndSave(cart: Cart): Promise<Cart> {
    cart.subtotal = cart.items.reduce(
      (sum, item) => sum + item.unitPrice * item.quantity,
      0,
    );

    cart.currency = cart.items[0]?.currency ?? cart.currency;
    cart.discountTotal = await this.promotions.calculateDiscount(cart);
    cart.taxTotal = await this.taxes.calculateTax(cart);
    cart.shippingTotal = cart.items.length > 0 ? 10 : 0;
    cart.grandTotal = Math.max(
      0,
      cart.subtotal - cart.discountTotal + cart.taxTotal + cart.shippingTotal,
    );
    cart.updatedAt = new Date();
    cart.version += 1;

    await this.repo.save(cart);
    return cart;
  }
}
```

### Service design
- **Core responsibilities**: create carts, add/update/remove items, apply coupons, merge guest carts, and freeze cart on checkout.
- **External dependencies**: catalog validates sellable items and pricing; promotion/tax services keep business logic out of the cart service.
- **Persistence**: repository abstraction supports DB choice and optimistic locking via `version`.
- **Key rules**:
  - only `ACTIVE` carts are editable
  - adding same SKU merges quantity
  - quantity `<= 0` removes the item in updates
  - guest cart merges into user cart on login
  - totals are always recomputed before save

### Suggested API surface
- `GET /carts/:id`
- `POST /carts/items`
- `PATCH /carts/:id/items/:productId`
- `POST /carts/:id/coupons`
- `POST /carts/merge`
- `POST /carts/:id/checkout`

### Storage sketch
- **carts**: `id, user_id, session_id, status, currency, subtotal, discount_total, tax_total, shipping_total, grand_total, version, created_at, updated_at`
- **cart_items**: `cart_id, product_id, sku, title, unit_price, quantity, currency`
