707.answer:
```js
import fs from 'node:fs/promises';

async function fetchAllUsers() {
  const users = [];
  const seenIds = new Set();
  let page = 1;

  while (true) {
    const res = await fetch(`https://api.example.com/v1/users?page=${page}`);
    if (!res.ok) {
      throw new Error(`Request failed for page ${page}: ${res.status} ${res.statusText}`);
    }

    const body = await res.json();
    const data = Array.isArray(body.data) ? body.data : [];

    if (data.length === 0) break;

    for (const user of data) {
      if (seenIds.has(user.id)) {
        throw new Error(`Duplicate user id found across pages: ${user.id}`);
      }
      seenIds.add(user.id);

      users.push({
        id: user.id,
        name: user.full_name,
        created_at: user.created_at,
      });
    }

    page += 1;
  }

  return users;
}

function csvEscape(value) {
  const s = String(value ?? '');
  return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}

async function writeCsv(users, outputPath = 'users.csv') {
  const lines = [
    'id,name,created_at',
    ...users.map(user => [user.id, user.name, user.created_at].map(csvEscape).join(',')),
  ];

  await fs.writeFile(outputPath, `${lines.join('\n')}\n`, 'utf8');
}

const users = await fetchAllUsers();
await writeCsv(users);
console.log(`Wrote ${users.length} users to users.csv`);
```

