A heap is a **complete binary tree** stored efficiently in an array, where each parent obeys an order rule with its children.

- **Min-heap:** parent <= children, so the smallest element is at the root.
- **Max-heap:** parent >= children, so the largest element is at the root.

For an array-based heap using 0-based indexing:
- parent of `i` = `(i - 1) / 2`
- left child of `i` = `2 * i + 1`
- right child of `i` = `2 * i + 2`

Why heaps are useful:
- `insert` takes **O(log n)**
- `extractMin` takes **O(log n)**
- `getMin` takes **O(1)**

The key maintenance operations are:
- **heapify up:** after insertion, move the new value upward until heap order is restored
- **heapify down:** after removing the root, move the replacement downward until heap order is restored

Here is a simple **min-heap in C++** with `insert`, `getMin`, and `extractMin` operations:

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

class MinHeap {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent] <= heap[index]) break;
            swap(heap[parent], heap[index]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int size = heap.size();

        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < size && heap[left] < heap[smallest]) {
                smallest = left;
            }
            if (right < size && heap[right] < heap[smallest]) {
                smallest = right;
            }

            if (smallest == index) break;
            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int getMin() const {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }
        return heap[0];
    }

    int extractMin() {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }

        int minValue = heap[0];
        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }

        return minValue;
    }

    bool empty() const {
        return heap.empty();
    }

    void print() const {
        for (int x : heap) {
            cout << x << " ";
        }
        cout << '\n';
    }
};

int main() {
    MinHeap h;

    h.insert(10);
    h.insert(4);
    h.insert(15);
    h.insert(2);
    h.insert(8);

    cout << "Min: " << h.getMin() << endl;        // 2
    cout << "Extract: " << h.extractMin() << endl; // 2
    cout << "Min now: " << h.getMin() << endl;     // 4

    h.print();
    return 0;
}
```

