The adapter pattern wraps an incompatible API with the interface your code expects. It lets existing code keep calling a clean target interface while the adapter translates requests and responses to and from the legacy system.

Why it’s useful:
- isolates legacy quirks in one place
- avoids changing client code
- makes gradual migration easier
- improves testability

In your case:
- **target interface**: JSON-based service
- **adaptee**: legacy XML service
- **adapter**: converts JSON requests to XML, calls the legacy service, then converts XML responses back to JSON

```ts
// Target interface expected by modern application code
interface UserJsonService {
  getUser(id: string): Promise<{ id: string; name: string; email: string }>;
}

// Legacy XML service we cannot change
class LegacyXmlUserService {
  async fetchUser(xmlRequest: string): Promise<string> {
    // Simulated legacy XML API
    // Example request: <GetUserRequest><Id>123</Id></GetUserRequest>

    const idMatch = xmlRequest.match(/<Id>(.*?)<\/Id>/);
    const id = idMatch?.[1] ?? "unknown";

    return `
      <User>
        <Id>${id}</Id>
        <Name>Jane Doe</Name>
        <Email>jane.doe@example.com</Email>
      </User>
    `.trim();
  }
}

// Adapter: makes the XML service look like the JSON interface
class XmlToJsonUserServiceAdapter implements UserJsonService {
  constructor(private legacyService: LegacyXmlUserService) {}

  async getUser(id: string): Promise<{ id: string; name: string; email: string }> {
    const xmlRequest = this.toXmlRequest(id);
    const xmlResponse = await this.legacyService.fetchUser(xmlRequest);
    return this.fromXmlResponse(xmlResponse);
  }

  private toXmlRequest(id: string): string {
    return `<GetUserRequest><Id>${this.escapeXml(id)}</Id></GetUserRequest>`;
  }

  private fromXmlResponse(xml: string): { id: string; name: string; email: string } {
    return {
      id: this.extractTag(xml, "Id"),
      name: this.extractTag(xml, "Name"),
      email: this.extractTag(xml, "Email"),
    };
  }

  private extractTag(xml: string, tag: string): string {
    const match = xml.match(new RegExp(`<${tag}>(.*?)<\\/${tag}>`));
    if (!match) {
      throw new Error(`Missing <${tag}> in XML response`);
    }
    return match[1];
  }

  private escapeXml(value: string): string {
    return value
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&apos;");
  }
}

// Client code depends only on the JSON interface
async function main() {
  const legacyXmlService = new LegacyXmlUserService();
  const userService: UserJsonService = new XmlToJsonUserServiceAdapter(legacyXmlService);

  const user = await userService.getUser("123");
  console.log(user);
  // { id: '123', name: 'Jane Doe', email: 'jane.doe@example.com' }
}

main().catch(console.error);
```

