The Template Method pattern defines the skeleton of an algorithm in a base class, while letting subclasses override specific steps without changing the overall flow.

### When to use it
- The high-level process is always the same
- Some steps vary by type or format
- You want to avoid duplicating shared workflow logic

### In this parser example
The base parser controls the sequence:
1. Load raw input
2. Parse it
3. Validate it
4. Transform it
5. Return the result

CSV and JSON parsers customize only the format-specific parsing step.

## C# implementation
```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;

public abstract class DataParser
{
    public List<Dictionary<string, string>> ParseData(string input)
    {
        string rawData = Load(input);
        var records = Parse(rawData);
        Validate(records);
        return Transform(records);
    }

    protected virtual string Load(string input)
    {
        return input?.Trim() ?? string.Empty;
    }

    protected abstract List<Dictionary<string, string>> Parse(string rawData);

    protected virtual void Validate(List<Dictionary<string, string>> records)
    {
        if (records == null || records.Count == 0)
        {
            throw new InvalidOperationException("No records found.");
        }
    }

    protected virtual List<Dictionary<string, string>> Transform(List<Dictionary<string, string>> records)
    {
        return records;
    }
}

public class CsvDataParser : DataParser
{
    protected override List<Dictionary<string, string>> Parse(string rawData)
    {
        var lines = rawData
            .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);

        if (lines.Length < 2)
        {
            return new List<Dictionary<string, string>>();
        }

        var headers = lines[0].Split(',').Select(h => h.Trim()).ToArray();
        var result = new List<Dictionary<string, string>>();

        for (int i = 1; i < lines.Length; i++)
        {
            var values = lines[i].Split(',').Select(v => v.Trim()).ToArray();
            var record = new Dictionary<string, string>();

            for (int j = 0; j < headers.Length; j++)
            {
                record[headers[j]] = j < values.Length ? values[j] : string.Empty;
            }

            result.Add(record);
        }

        return result;
    }
}

public class JsonDataParser : DataParser
{
    protected override List<Dictionary<string, string>> Parse(string rawData)
    {
        using var document = JsonDocument.Parse(rawData);
        var result = new List<Dictionary<string, string>>();

        if (document.RootElement.ValueKind != JsonValueKind.Array)
        {
            throw new InvalidOperationException("JSON input must be an array of objects.");
        }

        foreach (var item in document.RootElement.EnumerateArray())
        {
            if (item.ValueKind != JsonValueKind.Object)
            {
                continue;
            }

            var record = new Dictionary<string, string>();

            foreach (var property in item.EnumerateObject())
            {
                record[property.Name] = property.Value.ToString();
            }

            result.Add(record);
        }

        return result;
    }
}

public static class Program
{
    public static void Main()
    {
        string csvInput = @"
Name,Age,City
Alice,30,Paris
Bob,25,London";

        string jsonInput = @"[
  { ""Name"": ""Alice"", ""Age"": 30, ""City"": ""Paris"" },
  { ""Name"": ""Bob"", ""Age"": 25, ""City"": ""London"" }
]";

        DataParser csvParser = new CsvDataParser();
        DataParser jsonParser = new JsonDataParser();

        var csvRecords = csvParser.ParseData(csvInput);
        var jsonRecords = jsonParser.ParseData(jsonInput);

        PrintRecords("CSV Records", csvRecords);
        PrintRecords("JSON Records", jsonRecords);
    }

    private static void PrintRecords(string title, List<Dictionary<string, string>> records)
    {
        Console.WriteLine(title);
        foreach (var record in records)
        {
            Console.WriteLine(string.Join(", ", record.Select(kvp => $"{kvp.Key}: {kvp.Value}")));
        }
        Console.WriteLine();
    }
}
```

### Why this is Template Method
- `ParseData()` is the template method
- It defines the fixed algorithm
- `Parse()` is the required subclass-specific step
- `Load()`, `Validate()`, and `Transform()` are optional hooks subclasses can override

If you want, I can also show a version using strongly typed models instead of `Dictionary<string, string>`.

