The repository pattern abstracts data access behind a small interface so the rest of your code works with domain objects instead of storage details. It keeps business logic independent from persistence, makes testing easier, and lets you swap implementations later, like moving from in-memory storage to a database, without changing callers.

```python
from __future__ import annotations

from dataclasses import dataclass
from typing import Dict, Generic, List, Optional, Protocol, TypeVar


T = TypeVar("T")
ID = TypeVar("ID")


class Repository(Protocol[T, ID]):
    def add(self, entity: T) -> None:
        ...

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        ...

    def list_all(self) -> List[T]:
        ...


@dataclass(frozen=True)
class User:
    id: int
    name: str


class InMemoryRepository(Generic[T, ID]):
    def __init__(self, id_getter):
        self._items: Dict[ID, T] = {}
        self._id_getter = id_getter

    def add(self, entity: T) -> None:
        entity_id = self._id_getter(entity)
        self._items[entity_id] = entity

    def get_by_id(self, entity_id: ID) -> Optional[T]:
        return self._items.get(entity_id)

    def list_all(self) -> List[T]:
        return list(self._items.values())


if __name__ == "__main__":
    repo = InMemoryRepository[User, int](id_getter=lambda user: user.id)

    repo.add(User(id=1, name="Alice"))
    repo.add(User(id=2, name="Bob"))

    print(repo.get_by_id(1))
    print(repo.list_all())
```

If you want, I can also show the same pattern with an abstract base class, tests, or a version specialized for one entity type.

