Middleware chaining passes a request through a sequence of functions, where each middleware can inspect or modify the request/response, stop the flow, or call `next()` to hand off control to the next middleware. That pattern keeps concerns like logging, auth, and business logic separate and composable.

```js
function createMiddlewareChain(middlewares) {
  return async function run(req, res) {
    let index = -1;

    async function dispatch(i) {
      if (i <= index) throw new Error('next() called multiple times');
      index = i;

      const middleware = middlewares[i];
      if (!middleware) return;

      await middleware(req, res, () => dispatch(i + 1));
    }

    await dispatch(0);
    return res;
  };
}

const loggingMiddleware = async (req, res, next) => {
  console.log(`[LOG] ${req.method} ${req.url}`);
  await next();
};

const authMiddleware = async (req, res, next) => {
  const authHeader = req.headers?.authorization;

  if (authHeader !== 'Bearer secret-token') {
    res.statusCode = 401;
    res.body = { error: 'Unauthorized' };
    return;
  }

  req.user = { id: 1, role: 'admin' };
  await next();
};

const handlerMiddleware = async (req, res, next) => {
  res.statusCode = 200;
  res.body = {
    message: 'Request processed successfully',
    user: req.user ?? null,
  };
  await next();
};

const app = createMiddlewareChain([
  loggingMiddleware,
  authMiddleware,
  handlerMiddleware,
]);

async function simulateRequest(req) {
  const res = { statusCode: 404, body: null };
  await app(req, res);
  return res;
}

(async () => {
  const okResponse = await simulateRequest({
    method: 'GET',
    url: '/profile',
    headers: { authorization: 'Bearer secret-token' },
  });

  console.log('Authorized response:', okResponse);

  const deniedResponse = await simulateRequest({
    method: 'GET',
    url: '/profile',
    headers: { authorization: 'Bearer wrong-token' },
  });

  console.log('Unauthorized response:', deniedResponse);
})();
```

How it works:
- `createMiddlewareChain()` builds a dispatcher that runs middleware in order.
- Each middleware gets `(req, res, next)`.
- `loggingMiddleware` logs the request and continues.
- `authMiddleware` either rejects with `401` or attaches `req.user` and continues.
- `handlerMiddleware` produces the final response.
- If a middleware does not call `next()`, the chain stops there.

