Consistent hashing maps both nodes and keys onto the same circular hash space, so each key is assigned to the first node clockwise from its hash. When a node is added or removed, only the keys in the affected ring segment move, instead of almost all keys being remapped as with modulo-based sharding.

Virtual nodes improve balance by placing each physical node on the ring multiple times under different hashes. That smooths out uneven distribution, especially when the cluster is small or node capacities differ.

### Python implementation
```python
import hashlib
import bisect
from typing import Iterable, List, Dict


class ConsistentHashRing:
    def __init__(self, nodes: Iterable[str] = (), replicas: int = 100):
        if replicas <= 0:
            raise ValueError("replicas must be > 0")
        self.replicas = replicas
        self.ring: List[int] = []
        self.node_map: Dict[int, str] = {}
        self.nodes = set()

        for node in nodes:
            self.add_node(node)

    @staticmethod
    def _hash(value: str) -> int:
        return int(hashlib.md5(value.encode("utf-8")).hexdigest(), 16)

    def add_node(self, node: str) -> None:
        if node in self.nodes:
            return
        self.nodes.add(node)

        for replica in range(self.replicas):
            vnode_key = f"{node}#{replica}"
            h = self._hash(vnode_key)
            # Handle rare hash collisions deterministically
            while h in self.node_map:
                h = (h + 1) % (1 << 128)
            bisect.insort(self.ring, h)
            self.node_map[h] = node

    def remove_node(self, node: str) -> None:
        if node not in self.nodes:
            return
        self.nodes.remove(node)

        to_remove = [h for h, n in self.node_map.items() if n == node]
        for h in to_remove:
            idx = bisect.bisect_left(self.ring, h)
            if idx < len(self.ring) and self.ring[idx] == h:
                self.ring.pop(idx)
            del self.node_map[h]

    def get_node(self, key: str) -> str:
        if not self.ring:
            raise ValueError("hash ring is empty")

        h = self._hash(key)
        idx = bisect.bisect(self.ring, h)
        if idx == len(self.ring):
            idx = 0
        return self.node_map[self.ring[idx]]


if __name__ == "__main__":
    ring = ConsistentHashRing(["node-a", "node-b", "node-c"], replicas=200)

    keys = ["user:1", "user:2", "user:3", "session:abc"]
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")

    ring.add_node("node-d")
    print("After adding node-d:")
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")
```

### Why this works
- `add_node()` places many virtual nodes for each real node on the ring.
- `get_node()` hashes the key and finds the first vnode clockwise using binary search.
- If the search reaches the end, it wraps to the first ring entry.
- Adding/removing one node only changes ownership for nearby key ranges.

### Example property
If you move from 3 nodes to 4 nodes, roughly only about `1 / 4` of keys should move, rather than nearly all keys.

