```js
function deepClone(value, clones = new WeakMap()) {
  if (value === null || typeof value !== 'object') return value;

  if (clones.has(value)) return clones.get(value);

  if (value instanceof Date) return new Date(value.getTime());
  if (value instanceof RegExp) return new RegExp(value.source, value.flags);

  if (value instanceof Map) {
    const result = new Map();
    clones.set(value, result);
    for (const [key, entryValue] of value) {
      result.set(deepClone(key, clones), deepClone(entryValue, clones));
    }
    return result;
  }

  if (value instanceof Set) {
    const result = new Set();
    clones.set(value, result);
    for (const entry of value) {
      result.add(deepClone(entry, clones));
    }
    return result;
  }

  if (Array.isArray(value)) {
    const result = [];
    clones.set(value, result);
    for (const item of value) {
      result.push(deepClone(item, clones));
    }
    return result;
  }

  const result = Object.create(Object.getPrototypeOf(value));
  clones.set(value, result);

  for (const key of Reflect.ownKeys(value)) {
    const descriptor = Object.getOwnPropertyDescriptor(value, key);
    if (!descriptor) continue;

    if ('value' in descriptor) {
      descriptor.value = deepClone(descriptor.value, clones);
    }

    Object.defineProperty(result, key, descriptor);
  }

  return result;
}
```

This preserves circular references and shared references via the `WeakMap`, so if two parts of the original point to the same object, the clone points to the same cloned object too.

