function deepEqualStructural(a, b) {
  if (Object.is(a, b)) return true;

  const isObjectLike = (value) =>
    value !== null && (typeof value === 'object' || typeof value === 'function');

  if (!isObjectLike(a) || !isObjectLike(b)) return false;

  const seen = new WeakMap();
  const stack = [[a, b]];

  while (stack.length > 0) {
    const [left, right] = stack.pop();

    if (Object.is(left, right)) continue;
    if (!isObjectLike(left) || !isObjectLike(right)) return false;

    let leftSeen = seen.get(left);
    if (leftSeen) {
      if (leftSeen !== right) return false;
      continue;
    }
    seen.set(left, right);

    if (Object.getPrototypeOf(left) !== Object.getPrototypeOf(right)) return false;

    if (left instanceof Date || right instanceof Date) {
      if (!(left instanceof Date && right instanceof Date)) return false;
      if (!Object.is(left.getTime(), right.getTime())) return false;
      continue;
    }

    if (left instanceof RegExp || right instanceof RegExp) {
      if (!(left instanceof RegExp && right instanceof RegExp)) return false;
      if (left.source !== right.source || left.flags !== right.flags) return false;
      continue;
    }

    if (ArrayBuffer.isView(left) || ArrayBuffer.isView(right)) {
      if (!(ArrayBuffer.isView(left) && ArrayBuffer.isView(right))) return false;
      if (left.constructor !== right.constructor || left.length !== right.length) return false;
      for (let i = 0; i < left.length; i++) {
        if (!Object.is(left[i], right[i])) return false;
      }
      continue;
    }

    if (left instanceof ArrayBuffer || right instanceof ArrayBuffer) {
      if (!(left instanceof ArrayBuffer && right instanceof ArrayBuffer)) return false;
      if (left.byteLength !== right.byteLength) return false;
      const lv = new Uint8Array(left);
      const rv = new Uint8Array(right);
      for (let i = 0; i < lv.length; i++) {
        if (lv[i] !== rv[i]) return false;
      }
      continue;
    }

    if (left instanceof Map || right instanceof Map) {
      if (!(left instanceof Map && right instanceof Map)) return false;
      if (left.size !== right.size) return false;

      const rightEntries = Array.from(right.entries());
      const matched = new Array(rightEntries.length).fill(false);

      outerMap: for (const [lk, lv] of left) {
        for (let i = 0; i < rightEntries.length; i++) {
          if (matched[i]) continue;
          const [rk, rv] = rightEntries[i];
          if (!deepEqualStructural(lk, rk)) continue;
          if (!deepEqualStructural(lv, rv)) continue;
          matched[i] = true;
          continue outerMap;
        }
        return false;
      }
      continue;
    }

    if (left instanceof Set || right instanceof Set) {
      if (!(left instanceof Set && right instanceof Set)) return false;
      if (left.size !== right.size) return false;

      const rightValues = Array.from(right.values());
      const matched = new Array(rightValues.length).fill(false);

      outerSet: for (const lv of left) {
        for (let i = 0; i < rightValues.length; i++) {
          if (matched[i]) continue;
          if (!deepEqualStructural(lv, rightValues[i])) continue;
          matched[i] = true;
          continue outerSet;
        }
        return false;
      }
      continue;
    }

    const leftKeys = Reflect.ownKeys(left);
    const rightKeys = Reflect.ownKeys(right);

    if (leftKeys.length !== rightKeys.length) return false;

    for (const key of leftKeys) {
      if (!Object.prototype.propertyIsEnumerable.call(right, key) &&
          !Object.prototype.hasOwnProperty.call(right, key)) {
        return false;
      }
    }

    for (const key of leftKeys) {
      if (!Object.prototype.hasOwnProperty.call(right, key)) return false;

      const leftDesc = Object.getOwnPropertyDescriptor(left, key);
      const rightDesc = Object.getOwnPropertyDescriptor(right, key);

      if (!leftDesc || !rightDesc) return false;
      if (leftDesc.enumerable !== rightDesc.enumerable ||
          leftDesc.configurable !== rightDesc.configurable) {
        return false;
      }

      const leftIsData = Object.prototype.hasOwnProperty.call(leftDesc, 'value');
      const rightIsData = Object.prototype.hasOwnProperty.call(rightDesc, 'value');
      if (leftIsData !== rightIsData) return false;

      if (leftIsData) {
        if (leftDesc.writable !== rightDesc.writable) return false;
        stack.push([leftDesc.value, rightDesc.value]);
      } else {
        if (!Object.is(leftDesc.get, rightDesc.get) || !Object.is(leftDesc.set, rightDesc.set)) {
          return false;
        }
      }
    }
  }

  return true;
}
```

