```js
function flattenObject(input) {
  const out = {};

  const escapeSegment = (segment) =>
    String(segment)
      .replace(/\\/g, "\\\\")
      .replace(/\./g, "\\.");

  const joinPath = (segments) => segments.map(escapeSegment).join(".");

  const walk = (value, path) => {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[joinPath(path)] = [];
        return;
      }

      value.forEach((item, index) => {
        walk(item, [...path, String(index)]);
      });
      return;
    }

    if (value && typeof value === "object") {
      const entries = Object.entries(value);

      if (entries.length === 0) {
        out[joinPath(path)] = {};
        return;
      }

      for (const [key, child] of entries) {
        walk(child, [...path, key]);
      }
      return;
    }

    out[joinPath(path)] = value;
  };

  if (!input || typeof input !== "object" || Array.isArray(input)) {
    throw new TypeError("flattenObject expects a non-null plain object");
  }

  for (const [key, value] of Object.entries(input)) {
    walk(value, [key]);
  }

  return out;
}
```

Escaping strategy:
- Path separator is `.`.
- A literal `.` inside a key segment is escaped as `\.`.
- A literal backslash inside a key segment is escaped as `\\`.
- Escaping is applied per segment before joining with `.`.
- Array indexes are emitted as normal segments like `items.0.name`.

