```js
function unflatten(input) {
  const result = {};

  for (const [flatKey, value] of Object.entries(input)) {
    const parts = flatKey.split('.');
    let node = result;

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      const isLeaf = i === parts.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(node, part) &&
          node[part] !== undefined &&
          typeof node[part] === 'object' &&
          node[part] !== null
        ) {
          throw new Error(`Conflict at "${flatKey}": "${part}" is already an object`);
        }

        node[part] = value;
        continue;
      }

      if (Object.prototype.hasOwnProperty.call(node, part)) {
        if (node[part] === null || typeof node[part] !== 'object' || Array.isArray(node[part])) {
          throw new Error(`Conflict at "${flatKey}": "${part}" is already a value`);
        }
      } else {
        node[part] = {};
      }

      node = node[part];
    }
  }

  return result;
}
```

