```js
function decimalStringToBinary(decimal) {
  if (!/^[0-9]+$/.test(decimal)) throw new Error('Invalid decimal string');
  decimal = decimal.replace(/^0+/, '') || '0';
  if (decimal === '0') return '0';

  const digits = decimal.split('').map(ch => ch.charCodeAt(0) - 48);
  const bits = [];

  while (!(digits.length === 1 && digits[0] === 0)) {
    let carry = 0;
    let write = 0;

    for (let read = 0; read < digits.length; read++) {
      const value = carry * 10 + digits[read];
      const q = (value / 2) | 0;
      carry = value & 1;
      if (write > 0 || q !== 0) digits[write++] = q;
    }

    bits.push(carry);
    digits.length = write || 1;
    if (write === 0) digits[0] = 0;
  }

  return bits.reverse().join('');
}

// Example
console.log(decimalStringToBinary('13')); // 1101
console.log(decimalStringToBinary('0'));  // 0
```

It works by repeated long division on the decimal string, collecting remainders as binary bits. This uses only arrays of base-10 digits, so it preserves exact precision even for 100,000-digit inputs.

