    const { quotient, remainder } = div2Decimal(exp);
    if (remainder === 1) result = mulMod(result, base, mStr);
    base = mulMod(base, base, mStr);
    exp = quotient;
  }

  return result;
}

function normalize(s) {
  s = s.replace(/^0+/, "");
  return s === "" ? "0" : s;
}

function compare(a, b) {
  a = normalize(a);
  b = normalize(b);
  if (a.length !== b.length) return a.length < b.length ? -1 : 1;
  if (a === b) return 0;
  return a < b ? -1 : 1;
}

function sub(a, b) {
  a = a.split("").map(Number);
  b = b.split("").map(Number);
  let i = a.length - 1;
  let j = b.length - 1;
  let borrow = 0;
  let out = [];

  while (i >= 0) {
    let d = a[i] - borrow - (j >= 0 ? b[j] : 0);
    if (d < 0) {
      d += 10;
      borrow = 1;
    } else {
      borrow = 0;
    }
    out.push(d);
    i--;
    j--;
  }

  return normalize(out.reverse().join(""));
}

function modDecimal(num, mod) {
  let rem = "0";
  for (const ch of num) {
    rem = addDigitMul10(rem, ch.charCodeAt(0) - 48);
    while (compare(rem, mod) >= 0) rem = sub(rem, mod);
  }
  return rem;
}

function addDigitMul10(num, digit) {
  num = num === "0" ? "" : num;
  return normalize(num + digit.toString());
}

function div2Decimal(num) {
  let carry = 0;
  let q = "";
  for (const ch of num) {
    const cur = carry * 10 + (ch.charCodeAt(0) - 48);
    q += Math.floor(cur / 2);
    carry = cur % 2;
  }
  return { quotient: normalize(q), remainder: carry };
}

function addMod(a, b, mod) {
  let carry = 0;
  let i = a.length - 1;
  let j = b.length - 1;
  let out = [];

  while (i >= 0 || j >= 0 || carry) {
    const x = i >= 0 ? a.charCodeAt(i) - 48 : 0;
    const y = j >= 0 ? b.charCodeAt(j) - 48 : 0;
    const s = x + y + carry;
    out.push(s % 10);
    carry = Math.floor(s / 10);
    i--;
    j--;
  }

  let sum = normalize(out.reverse().join(""));
  while (compare(sum, mod) >= 0) sum = sub(sum, mod);
  return sum;
}

function mulMod(a, b, mod) {
  let result = "0";
  let x = a;
  let y = b;

  while (y !== "0") {
    const { quotient, remainder } = div2Decimal(y);
    if (remainder === 1) result = addMod(result, x, mod);
    x = addMod(x, x, mod);
    y = quotient;
  }

  return result;
}
