```js
function roundDecimalString(value, places) {
  const match = String(value).trim().match(/^([+-]?)(\d+)(?:\.(\d*))?$/);
  if (!match) throw new Error('Invalid decimal string');
  if (!Number.isInteger(places) || places < 0) throw new Error('Invalid places');

  const [, sign, intPart, fracPartRaw = ''] = match;
  const fracPart = fracPartRaw;

  if (places >= fracPart.length) {
    return sign + intPart + (places ? '.' + fracPart.padEnd(places, '0') : '');
  }

  const keptFrac = fracPart.slice(0, places);
  const nextDigit = fracPart.charCodeAt(places) - 48;
  const rest = fracPart.slice(places + 1);

  let roundUp = false;

  if (nextDigit > 5) {
    roundUp = true;
  } else if (nextDigit < 5) {
    roundUp = false;
  } else {
    const hasTrailingNonZero = /[1-9]/.test(rest);
    if (hasTrailingNonZero) {
      roundUp = true;
    } else {
      const lastKeptDigit = places > 0
        ? Number(keptFrac[places - 1])
        : Number(intPart[intPart.length - 1]);
      roundUp = lastKeptDigit % 2 !== 0;
    }
  }

  let digits = intPart + keptFrac;
  if (digits === '') digits = '0';

  if (roundUp) {
    let carry = 1;
    let out = '';
    for (let i = digits.length - 1; i >= 0; i--) {
      const sum = (digits.charCodeAt(i) - 48) + carry;
      if (sum === 10) {
        out = '0' + out;
        carry = 1;
      } else {
        out = String(sum) + out;
        carry = 0;
      }
    }
    if (carry) out = '1' + out;
    digits = out;
  }

  const wholeLen = digits.length - places;
  const whole = wholeLen > 0 ? digits.slice(0, wholeLen) : '0';
  const frac = wholeLen > 0 ? digits.slice(wholeLen) : digits.padStart(places, '0');

  return sign + whole + (places ? '.' + frac.padEnd(places, '0') : '');
}

// tests
console.log(roundDecimalString('1.25', 1)); // 1.2
console.log(roundDecimalString('1.35', 1)); // 1.4
console.log(roundDecimalString('2.25', 1)); // 2.2
console.log(roundDecimalString('2.35', 1)); // 2.4
console.log(roundDecimalString('1.2500', 1)); // 1.2
console.log(roundDecimalString('1.2501', 1)); // 1.3
```

