Use an epsilon-based comparison policy, never raw `==` on computed floats.

```js
function nearlyEqual(a, b, { abs = 1e-9, rel = 1e-12 } = {}) {
  const diff = Math.abs(a - b);
  if (diff <= abs) return true;
  return diff <= Math.max(Math.abs(a), Math.abs(b)) * rel;
}

function evalRule(actual, op, expected, tolerance) {
  switch (op) {
    case "==":
      return nearlyEqual(actual, expected, tolerance);
    case "!=":
      return !nearlyEqual(actual, expected, tolerance);
    case "<=":
      return actual < expected || nearlyEqual(actual, expected, tolerance);
    case ">=":
      return actual > expected || nearlyEqual(actual, expected, tolerance);
    case "<":
      return actual < expected && !nearlyEqual(actual, expected, tolerance);
    case ">":
      return actual > expected && !nearlyEqual(actual, expected, tolerance);
    default:
      throw new Error(`Unsupported operator: ${op}`);
  }
}
```

Example:

```js
const total = 0.1 + 0.2;
console.log(total === 0.3); // false
console.log(evalRule(total, "==", 0.3)); // true
```

Recommended tolerance policy for a rules engine:
- Use `abs` tolerance for values near zero.
- Use `rel` tolerance for larger magnitudes.
- Make tolerance explicit in rule evaluation config, not hardcoded per rule.
- Document that equality means “equal within tolerance,” not bit-exact equality.

