Use end-of-month clamping: add one calendar month by keeping the same day number when possible, otherwise clamp to the last day of the target month.

```js
function addOneCalendarMonth(date) {
  const year = date.getFullYear();
  const month = date.getMonth();
  const day = date.getDate();

  const targetYear = month === 11 ? year + 1 : year;
  const targetMonth = (month + 1) % 12;
  const lastDayOfTargetMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
  const targetDay = Math.min(day, lastDayOfTargetMonth);

  return new Date(
    targetYear,
    targetMonth,
    targetDay,
    date.getHours(),
    date.getMinutes(),
    date.getSeconds(),
    date.getMilliseconds()
  );
}
```

