```js
import assert from 'node:assert/strict';

assert.equal(
  addOneCalendarMonth(new Date(2025, 0, 31)).toDateString(),
  new Date(2025, 1, 28).toDateString()
); // Jan 31 -> Feb 28

assert.equal(
  addOneCalendarMonth(new Date(2024, 0, 31)).toDateString(),
  new Date(2024, 1, 29).toDateString()
); // Jan 31 -> Feb 29 (leap year)

assert.equal(
