Use a strict parser that accepts full ISO 8601 datetimes with optional fractional seconds and either an explicit offset or no timezone, while rejecting malformed inputs.

```js
const ISO_8601_STRICT = /^(?<year>\d{4})-(?<month>0[1-9]|1[0-2])-(?<day>0[1-9]|[12]\d|3[01])T(?<hour>[01]\d|2[0-3]):(?<minute>[0-5]\d)(?::(?<second>[0-5]\d)(?<fraction>\.\d{1,9})?)?(?<tz>Z|[+-](?:[01]\d|2[0-3]):[0-5]\d)?$/;

function parseIsoTimestamp(input, { naive = 'reject' } = {}) {
  const m = ISO_8601_STRICT.exec(input);
  if (!m) throw new Error('Invalid ISO 8601 timestamp');

  const { year, month, day, hour, minute, second, fraction, tz } = m.groups;
  const y = Number(year);
  const mo = Number(month);
  const d = Number(day);
  const h = Number(hour);
  const mi = Number(minute);
  const s = second ? Number(second) : 0;
  const frac = fraction ? fraction.slice(1) : '';

  if (!isValidUtcDateParts(y, mo, d, h, mi, s)) {
    throw new Error('Invalid calendar date/time');
  }

  if (!tz) {
    if (naive === 'reject') throw new Error('Timezone is required');
    if (naive === 'local') {
      return {
        kind: 'local',
        year: y,
        month: mo,
        day: d,
        hour: h,
        minute: mi,
        second: s,
        fractionalSeconds: frac,
      };
    }
    if (naive === 'utc') {
      return new Date(Date.UTC(y, mo - 1, d, h, mi, s, toMillis(frac)));
    }
    throw new Error(`Unsupported naive mode: ${naive}`);
  }

  if (tz === 'Z') {
    return new Date(Date.UTC(y, mo - 1, d, h, mi, s, toMillis(frac)));
  }

  const sign = tz[0] === '+' ? 1 : -1;
  const [offHour, offMinute] = tz.slice(1).split(':').map(Number);
  const offsetMinutes = sign * (offHour * 60 + offMinute);
  const utcMs = Date.UTC(y, mo - 1, d, h, mi, s, toMillis(frac)) - offsetMinutes * 60_000;
  return new Date(utcMs);
}

function toMillis(frac) {
  if (!frac) return 0;
  return Number((frac + '000').slice(0, 3));
}

function isValidUtcDateParts(y, mo, d, h, mi, s) {
  const dt = new Date(Date.UTC(y, mo - 1, d, h, mi, s));
  return (
    dt.getUTCFullYear() === y &&
    dt.getUTCMonth() === mo - 1 &&
    dt.getUTCDate() === d &&
    dt.getUTCHours() === h &&
    dt.getUTCMinutes() === mi &&
    dt.getUTCSeconds() === s
  );
}
```

Accepted examples:
- `2026-03-29T12:34Z`
- `2026-03-29T12:34:56Z`
- `2026-03-29T12:34:56.123Z`
- `2026-03-29T12:34:56+02:00`
- `2026-03-29T12:34:56.123456-05:30`
- `2026-03-29T12:34:56` if `naive` is set to `local` or `utc`

Rejected examples:
- missing date/time separator: `2026-03-29 12:34:56Z`
- basic format if you don’t support it: `20260329T123456Z`
- invalid offset: `2026-03-29T12:34:56+2:00`
- invalid date: `2026-02-30T12:00:00Z`
- stray commas / malformed forms like `,` or empty timezone markers

Recommended naive behavior:
- Default: `reject` missing timezone, because naive datetimes are ambiguous.
- If your product must accept them, choose exactly one policy and document it:
  - `local`: interpret as wall-clock time in the server/client locale.
  - `utc`: interpret as UTC.
- Don’t silently switch between local and UTC based on environment.

