function normalizeTimeToMinutes(value) {
  if (typeof value === 'number' && Number.isFinite(value)) {
    const minutes = value % 1440;
    return minutes < 0 ? minutes + 1440 : minutes;
  }

  const match = /^([01]?\d|2[0-3]):([0-5]\d)$/.exec(String(value));
  if (!match) throw new Error('Invalid time value');
  return Number(match[1]) * 60 + Number(match[2]);
}

function expandInterval(interval) {
  const start = normalizeTimeToMinutes(interval.start);
  const end = normalizeTimeToMinutes(interval.end);

  if (start === end) {
    return [{
      start,
      end,
      startInclusive: interval.startInclusive !== false,
      endInclusive: interval.endInclusive !== false,
    }];
  }

  if (start < end) {
    return [{
      start,
      end,
      startInclusive: interval.startInclusive !== false,
      endInclusive: interval.endInclusive !== false,
    }];
  }

  return [
    {
      start,
      end: 1440,
      startInclusive: interval.startInclusive !== false,
      endInclusive: false,
    },
    {
      start: 0,
      end,
      startInclusive: true,
      endInclusive: interval.endInclusive !== false,
    },
  ];
}

function segmentOverlaps(a, b) {
  const left = Math.max(a.start, b.start);
  const right = Math.min(a.end, b.end);

  if (left < right) return true;
  if (left > right) return false;

  const aIncludes = left === a.start ? a.startInclusive : a.endInclusive;
  const bIncludes = left === b.start ? b.startInclusive : b.endInclusive;
  return aIncludes && bIncludes;
}

function intervalsOverlap(a, b) {
  const aParts = expandInterval(a);
  const bParts = expandInterval(b);

  for (const aPart of aParts) {
    for (const bPart of bParts) {
      if (segmentOverlaps(aPart, bPart)) return true;
    }
  }

  return false;
}
```

