```ts
export type PaginationResult = {
  page: bigint;
  pageSize: bigint;
  totalItems: bigint;
  totalPages: bigint;
  hasPrevious: boolean;
  hasNext: boolean;
  offset: bigint;
  limit: bigint;
  isValid: boolean;
  error: null | 'INVALID_PAGE_SIZE' | 'INVALID_PAGE_NUMBER' | 'PAGE_OUT_OF_RANGE';
};

export function paginate(
  totalItems: bigint | number,
  page: bigint | number,
  pageSize: bigint | number,
): PaginationResult {
  const total = BigInt(totalItems);
  const currentPage = BigInt(page);
  const size = BigInt(pageSize);

  if (total < 0n) {
    throw new RangeError('totalItems must be >= 0');
  }

  if (size <= 0n) {
    return {
      page: currentPage,
      pageSize: size,
      totalItems: total,
      totalPages: 0n,
      hasPrevious: false,
      hasNext: false,
      offset: 0n,
      limit: 0n,
      isValid: false,
      error: 'INVALID_PAGE_SIZE',
    };
  }

  if (currentPage < 1n) {
    return {
      page: currentPage,
      pageSize: size,
      totalItems: total,
      totalPages: total === 0n ? 0n : (total + size - 1n) / size,
      hasPrevious: false,
      hasNext: false,
      offset: 0n,
      limit: 0n,
      isValid: false,
      error: 'INVALID_PAGE_NUMBER',
    };
  }

  const totalPages = total === 0n ? 0n : (total + size - 1n) / size;

  if (totalPages > 0n && currentPage > totalPages) {
    return {
      page: currentPage,
      pageSize: size,
      totalItems: total,
      totalPages,
      hasPrevious: false,
      hasNext: false,
      offset: 0n,
      limit: 0n,
      isValid: false,
      error: 'PAGE_OUT_OF_RANGE',
    };
  }

  if (totalPages === 0n) {
    return {
      page: currentPage,
      pageSize: size,
      totalItems: total,
      totalPages: 0n,
      hasPrevious: false,
      hasNext: false,
      offset: 0n,
      limit: 0n,
      isValid: true,
      error: null,
    };
  }

  const offset = (currentPage - 1n) * size;
  const remaining = total - offset;
  const limit = remaining < size ? remaining : size;

  return {
    page: currentPage,
    pageSize: size,
    totalItems: total,
    totalPages,
    hasPrevious: currentPage > 1n,
    hasNext: currentPage < totalPages,
    offset,
    limit,
    isValid: true,
    error: null,
  };
}
```

Exact invalid-return behavior:

- `pageSize <= 0` → `isValid: false`, `error: 'INVALID_PAGE_SIZE'`, `totalPages: 0n`, `offset: 0n`, `limit: 0n`
- `page < 1` → `isValid: false`, `error: 'INVALID_PAGE_NUMBER'`, `offset: 0n`, `limit: 0n`
- `page > totalPages` when `totalItems > 0` → `isValid: false`, `error: 'PAGE_OUT_OF_RANGE'`, `offset: 0n`, `limit: 0n`
- empty dataset (`totalItems === 0`) with valid `pageSize` and `page >= 1` → valid result with `totalPages: 0n`, `offset: 0n`, `limit: 0n`

Examples:

```ts
paginate(0n, 1n, 25n)
// => valid, totalPages=0n, offset=0n, limit=0n

paginate(100n, 0n, 25n)
// => invalid, error='INVALID_PAGE_NUMBER'

paginate(100n, -2n, 25n)
// => invalid, error='INVALID_PAGE_NUMBER'

paginate(100n, 1n, 0n)
// => invalid, error='INVALID_PAGE_SIZE'

paginate(10_000_000_000n, 400_000_000n, 25n)
// works safely because all arithmetic uses BigInt
```

