```js
function binarySearchFirst(arr, target, compare = defaultCompare) {
  let left = 0;
  let right = arr.length - 1;
  let result = -1;

  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);
    const order = compare(arr[mid], target);

    if (order < 0) {
      left = mid + 1;
    } else {
      if (order === 0) result = mid;
      right = mid - 1;
    }
  }

  return result;
}

function defaultCompare(a, b) {
  if (a < b) return -1;
  if (a > b) return 1;
  return 0;
}
```

Comparison policy: `compare(a, b)` must return a negative number if `a < b`, `0` if equal, and a positive number if `a > b`. The array must already be sorted according to that same policy. If duplicates exist, this returns the **first** matching index; otherwise it returns `-1`.

