function parseAndValidateIPv6(input) {
  if (typeof input !== 'string') return { valid: false, error: 'Input must be a string' };

  const s = input.trim();
  if (!s) return { valid: false, error: 'Empty input' };

  const lower = s.toLowerCase();
  if ((lower.match(/::/g) || []).length > 1) {
    return { valid: false, error: 'Invalid IPv6: multiple compression sequences' };
  }

  const hasIpv4 = s.includes('.');
  let working = lower;

  let ipv4Tail = null;
  if (hasIpv4) {
    const lastColon = working.lastIndexOf(':');
    if (lastColon === -1) {
      return { valid: false, error: 'Invalid IPv6: malformed IPv4-mapped tail' };
    }

    const ipv4Part = working.slice(lastColon + 1);
    const parsedIpv4 = parseIPv4(ipv4Part);
    if (!parsedIpv4.valid) {
      return { valid: false, error: 'Invalid IPv6: malformed embedded IPv4' };
    }

    ipv4Tail = parsedIpv4.bytes;
    working = working.slice(0, lastColon) + ':' +
      ((ipv4Tail[0] << 8) | ipv4Tail[1]).toString(16) + ':' +
      ((ipv4Tail[2] << 8) | ipv4Tail[3]).toString(16);
  }

  const parts = expandIPv6(working);
  if (!parts.valid) return parts;

  const hextets = parts.hextets;
  const canonical = compressIPv6(hextets);

  return {
    valid: true,
    canonical,
    expanded: hextets.map(h => h.padStart(4, '0')).join(':'),
    hextets,
    bytes: hextets.flatMap(h => {
      const n = parseInt(h, 16);
      return [(n >> 8) & 0xff, n & 0xff];
    }),
    kind: ipv4Tail ? 'ipv4-embedded' : 'ipv6'
  };
}

function parseIPv4(s) {
  const parts = s.split('.');
  if (parts.length !== 4) return { valid: false };

  const bytes = [];
  for (const part of parts) {
    if (!/^\d+$/.test(part)) return { valid: false };
    if (part.length > 1 && part[0] === '0') return { valid: false };
    const n = Number(part);
    if (n < 0 || n > 255) return { valid: false };
    bytes.push(n);
  }

  return { valid: true, bytes };
}

function expandIPv6(s) {
  const halves = s.split('::');
  if (halves.length > 2) {
    return { valid: false, error: 'Invalid IPv6: multiple compression sequences' };
  }

  const left = halves[0] ? halves[0].split(':') : [];
  const right = halves[1] ? halves[1].split(':') : [];

  if (![...left, ...right].every(isValidHextet)) {
    return { valid: false, error: 'Invalid IPv6: bad hextet' };
  }

  let hextets;
  if (halves.length === 1) {
    if (left.length !== 8) {
      return { valid: false, error: 'Invalid IPv6: must contain 8 hextets without compression' };
    }
    hextets = left;
  } else {
    const missing = 8 - (left.length + right.length);
    if (missing < 1) {
      return { valid: false, error: 'Invalid IPv6: compression does not shorten address' };
    }
    hextets = [...left, ...Array(missing).fill('0'), ...right];
  }

  if (hextets.length !== 8) {
    return { valid: false, error: 'Invalid IPv6: wrong number of hextets' };
  }

  return {
    valid: true,
    hextets: hextets.map(h => String(parseInt(h, 16) || 0).toString(16))
  };
}

function isValidHextet(h) {
  return /^[0-9a-f]{1,4}$/i.test(h);
}

function compressIPv6(hextets) {
  const normalized = hextets.map(h => h.toLowerCase().replace(/^0+/, '') || '0');

  let bestStart = -1;
  let bestLen = 0;
  let curStart = -1;
  let curLen = 0;

  for (let i = 0; i <= normalized.length; i++) {
    if (i < normalized.length && normalized[i] === '0') {
      if (curStart === -1) curStart = i;
      curLen++;
    } else {
      if (curLen > bestLen && curLen >= 2) {
        bestStart = curStart;
        bestLen = curLen;
      }
      curStart = -1;
      curLen = 0;
    }
  }

  if (bestStart === -1) return normalized.join(':');

  const left = normalized.slice(0, bestStart).join(':');
  const right = normalized.slice(bestStart + bestLen).join(':');

  if (!left && !right) return '::';
  if (!left) return '::' + right;
  if (!right) return left + '::';
  return left + '::' + right;
}

// Examples:
console.log(parseAndValidateIPv6('2001:0DB8:0000:0000:0000:ff00:0042:8329').canonical);
// 2001:db8::ff00:42:8329

console.log(parseAndValidateIPv6('::FFFF:192.168.0.1').canonical);
// ::ffff:c0a8:1

console.log(parseAndValidateIPv6('2001::db8::1'));
// { valid: false, error: 'Invalid IPv6: multiple compression sequences' }
```

Canonical form rules used:
- lowercase hex
- no leading zeros in hextets
- longest zero run compressed with `::`
- ties compressed using the leftmost run
- embedded IPv4 normalized to pure IPv6 canonical hex form

