class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

class LRUCache {
  constructor(capacity) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new Error('capacity must be a non-negative integer');
    }

    this.capacity = capacity;
    this.map = new Map();
    this.head = new Node(null, null);
    this.tail = new Node(null, null);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    const node = this.map.get(key);
    if (!node) return undefined;
    this.#moveToFront(node);
    return node.value;
  }

  put(key, value) {
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing) {
      existing.value = value;
      this.#moveToFront(existing);
      return;
    }

    const node = new Node(key, value);
    this.map.set(key, node);
    this.#insertAfterHead(node);

    if (this.map.size > this.capacity) {
      const lru = this.tail.prev;
      this.#removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  has(key) {
    return this.map.has(key);
  }

  #moveToFront(node) {
    this.#removeNode(node);
    this.#insertAfterHead(node);
  }

  #insertAfterHead(node) {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next.prev = node;
    this.head.next = node;
  }

  #removeNode(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }
}

// Minimal verification
(function test() {
  const assert = (condition, message) => {
    if (!condition) throw new Error(message);
  };

  // capacity 0
  const zero = new LRUCache(0);
  zero.put('a', 1);
  assert(zero.get('a') === undefined, 'capacity 0 should never store values');
  assert(zero.has('a') === false, 'capacity 0 should not retain keys');

  // capacity 1 eviction
  const one = new LRUCache(1);
  one.put('a', 'x');
  one.put('b', 'y');
  assert(one.get('a') === undefined, 'capacity 1 should evict previous key');
  assert(one.get('b') === 'y', 'capacity 1 should keep latest key');

  // repeated inserts of same key
  const repeated = new LRUCache(2);
  repeated.put('k', 1);
  repeated.put('k', 2);
  repeated.put('k', 3);
  assert(repeated.get('k') === 3, 'same key should update value');
  assert(repeated.map.size === 1, 'same key should not create duplicate entries');

  // falsy stored values
  const falsy = new LRUCache(2);
  falsy.put('empty', '');
  falsy.put('nil', null);
  assert(falsy.get('empty') === '', 'should return empty string values correctly');
  assert(falsy.get('nil') === null, 'should return null values correctly');

  console.log('All tests passed');
})();
