function dedupeByDeepContent(items) {
  const seen = new Set();
  const result = [];

  for (const item of items) {
    const key = canonicalize(item);
    if (!seen.has(key)) {
      seen.add(key);
      result.push(item);
    }
  }

  return result;
}

function canonicalize(value) {
  if (value === null) return 'null';

  const type = typeof value;

  if (type === 'string') {
    return `s:${JSON.stringify(value.normalize('NFC'))}`;
  }

  if (type === 'number') {
    if (Number.isNaN(value)) return 'n:NaN';
    if (!Number.isFinite(value)) return `n:${value}`;
    return `n:${Object.is(value, -0) ? '0' : String(value)}`;
  }

  if (type === 'boolean') return `b:${value}`;
  if (type === 'bigint') return `bi:${value}`;
  if (type === 'undefined') return 'u:undefined';

  if (Array.isArray(value)) {
    return `a:[${value.map(canonicalize).join(',')}]`;
  }

  if (type === 'object') {
    const keys = Object.keys(value).sort();
    return `o:{${keys
      .map((key) => `${JSON.stringify(key.normalize('NFC'))}:${canonicalize(value[key])}`)
      .join(',')}}`;
  }

  throw new TypeError(`Unsupported value type: ${type}`);
}

// Example
