  { a: 1, b: 'café' },
  { b: 'cafe\u0301', a: 1.0 },
  { a: 2 },
  { a: 2.000 }
];

console.log(dedupeByDeepContent(input));
// => [ { a: 1, b: 'café' }, { a: 2 } ]
```

