function serializeFormData(input) {
  const pairs = [];

  const encodeKeyPart = (part) =>
    encodeURIComponent(String(part)).replace(/%5B/g, '[').replace(/%5D/g, ']');

  const encodeLiteralKey = (key) => encodeURIComponent(String(key));

  const addPair = (key, value) => {
    const normalized = value === null ? '' : String(value);
    pairs.push(`${key}=${encodeURIComponent(normalized)}`);
  };

  const visit = (value, keyPath, topLevelLiteral = false) => {
    if (Array.isArray(value)) {
      for (const item of value) {
        visit(item, `${keyPath}[]`);
      }
      return;
    }

    if (value !== null && typeof value === 'object') {
      for (const [childKey, childValue] of Object.entries(value)) {
        const nextKey = keyPath
          ? `${keyPath}[${encodeKeyPart(childKey)}]`
          : topLevelLiteral
            ? encodeLiteralKey(childKey)
            : encodeKeyPart(childKey);
        visit(childValue, nextKey, false);
      }
      return;
    }

    addPair(keyPath, value);
  };

  if (input instanceof URLSearchParams) {
    return input.toString();
  }

  if (Array.isArray(input)) {
    for (const entry of input) {
      if (!Array.isArray(entry) || entry.length !== 2) {
        throw new TypeError('Array input must contain [key, value] tuples');
      }
      const [key, value] = entry;
      visit(value, encodeLiteralKey(key), true);
    }
    return pairs.join('&');
  }

  if (input && typeof input === 'object') {
    for (const [key, value] of Object.entries(input)) {
      visit(value, encodeLiteralKey(key), true);
    }
    return pairs.join('&');
  }

  throw new TypeError('Expected an object, URLSearchParams, or [key, value][] input');
}
```

Example:

```js
serializeFormData({
  name: '',
  active: false,
  meta: { ok: true, note: null },
  tags: ['a', 'b'],
  'x[y]': 'literal brackets',
});
// name=&active=false&meta[ok]=true&meta[note]=&tags[]=a&tags[]=b&x%5By%5D=literal%20brackets
```

Notes:
- Arrays use `[]` suffixes.
- `null` becomes an empty value.
- Empty strings stay empty.
- Booleans serialize as `true` / `false`.
- Duplicate keys are supported via tuple input like `[['a', 1], ['a', 2]]`.
- Top-level keys containing brackets are encoded literally, so `x[y]` becomes `x%5By%5D` instead of nested syntax.

