import { createHash } from 'node:crypto';

export function stableHash(value, algorithm = 'sha256') {
  const seen = new Map();
  let nextId = 0;

  const serialize = (input) => {
    if (input === null) return 'null';

    const type = typeof input;

    if (type === 'number') {
      if (Number.isNaN(input)) return 'number:NaN';
      if (input === Infinity) return 'number:Infinity';
      if (input === -Infinity) return 'number:-Infinity';
      if (Object.is(input, -0)) return 'number:-0';
      return `number:${input}`;
    }

    if (type === 'string') return `string:${JSON.stringify(input)}`;
    if (type === 'boolean') return `boolean:${input}`;
    if (type === 'undefined') return 'undefined';
    if (type === 'bigint') return `bigint:${input}n`;
    if (type === 'symbol') {
      throw new TypeError('Cannot hash symbol values');
    }
    if (type === 'function') {
      throw new TypeError('Cannot hash function values');
    }

    if (seen.has(input)) {
      return `ref:${seen.get(input)}`;
    }

    const id = nextId++;
    seen.set(input, id);

    if (Array.isArray(input)) {
      return `array#${id}[${input.map(serialize).join(',')}]`;
    }

    if (input instanceof Date) {
      return `date#${id}:${Number.isNaN(input.getTime()) ? 'Invalid' : input.toISOString()}`;
    }

    if (input instanceof RegExp) {
      return `regexp#${id}:${input.toString()}`;
    }

    const keys = Object.keys(input).sort();
    const entries = keys.map((key) => `${JSON.stringify(key)}:${serialize(input[key])}`);
    return `object#${id}{${entries.join(',')}}`;
  };

  const canonical = serialize(value);
  return createHash(algorithm).update(canonical).digest('hex');
}
```

