function diffJsonLike(left, right) {
  const changes = [];
  const seen = new WeakMap();

  walk(left, right, []);
  return changes;

  function walk(a, b, path) {
    if (Object.is(a, b)) return;

    const aIsObj = isObjectLike(a);
    const bIsObj = isObjectLike(b);

    if (!aIsObj || !bIsObj) {
      changes.push({
        path: formatPath(path),
        kind: 'change',
        before: a,
        after: b,
        reason: typeTag(a) !== typeTag(b) ? 'type' : 'value',
      });
      return;
    }

    if (isCircularPair(a, b)) {
      changes.push({
        path: formatPath(path),
        kind: 'change',
        before: '[Circular]',
        after: '[Circular]',
        reason: 'circular',
      });
      return;
    }

    rememberPair(a, b);

    const aTag = typeTag(a);
    const bTag = typeTag(b);
    if (aTag !== bTag) {
      changes.push({
        path: formatPath(path),
        kind: 'change',
        before: a,
        after: b,
        reason: 'type',
      });
      return;
    }

    if (Array.isArray(a)) {
      diffArray(a, b, path);
      return;
    }

    diffObject(a, b, path);
  }

  function diffObject(a, b, path) {
    const keys = new Set([...Reflect.ownKeys(a), ...Reflect.ownKeys(b)]);

    for (const key of keys) {
      const aHas = Object.prototype.hasOwnProperty.call(a, key);
      const bHas = Object.prototype.hasOwnProperty.call(b, key);
      const nextPath = path.concat(key);

      if (!aHas && bHas) {
        changes.push({
          path: formatPath(nextPath),
          kind: 'add',
          after: b[key],
        });
        continue;
      }

      if (aHas && !bHas) {
        changes.push({
          path: formatPath(nextPath),
          kind: 'delete',
          before: a[key],
        });
        continue;
      }

      walk(a[key], b[key], nextPath);
    }
  }

  function diffArray(a, b, path) {
    const max = Math.max(a.length, b.length);

    for (let i = 0; i < max; i++) {
      const aHas = i in a;
      const bHas = i in b;
      const nextPath = path.concat(i);

      if (!aHas && bHas) {
        changes.push({
          path: formatPath(nextPath),
          kind: 'add',
          after: b[i],
        });
        continue;
      }

      if (aHas && !bHas) {
        changes.push({
          path: formatPath(nextPath),
          kind: 'delete',
          before: a[i],
        });
        continue;
      }

      walk(a[i], b[i], nextPath);
    }

    if (a.length !== b.length) {
      changes.push({
        path: formatPath(path.concat('length')),
        kind: 'change',
        before: a.length,
        after: b.length,
        reason: 'length',
      });
    }
  }

  function isObjectLike(value) {
    return value !== null && typeof value === 'object';
  }

  function typeTag(value) {
    if (Array.isArray(value)) return 'array';
    if (value === null) return 'null';
    return typeof value;
  }

  function rememberPair(a, b) {
    let inner = seen.get(a);
    if (!inner) {
      inner = new WeakSet();
      seen.set(a, inner);
    }
    inner.add(b);
  }

  function isCircularPair(a, b) {
    const inner = seen.get(a);
    return inner ? inner.has(b) : false;
  }

  function formatPath(segments) {
    if (segments.length === 0) return '$';

    let out = '$';
    for (const segment of segments) {
      if (typeof segment === 'number') {
        out += `[${segment}]`;
      } else if (typeof segment === 'symbol') {
        out += `[${String(segment)}]`;
      } else if (/^[A-Za-z_$][A-Za-z0-9_$]*$/.test(segment)) {
        out += `.${segment}`;
      } else {
        out += `[${JSON.stringify(segment)}]`;
      }
    }
    return out;
  }
}

// Example:
const a = { user: { name: 'Ada' }, list: [1, , 3] };
const b = { user: { name: 'Grace' }, list: [1, 2], extra: true };

a.self = a;
b.self = b;

console.log(diffJsonLike(a, b));
```

Notes:
- Paths use a JSONPath-like format such as `$.user.name` and `$.list[1]`.
- Sparse arrays are handled via `i in array`, so holes differ from explicit `undefined`.
- Circular references are detected per compared object pair to avoid infinite recursion.
- This reports additions, deletions, value changes, type changes, and array length changes.

