import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.ByteBuffer;
import java.nio.CharBuffer;
import java.nio.charset.CharacterCodingException;
import java.nio.charset.CodingErrorAction;
import java.nio.charset.StandardCharsets;

public static String readUtf8Body(InputStream bodyStream, int maxBytes)
        throws IOException, CharacterCodingException {
    ByteArrayOutputStream buffer = new ByteArrayOutputStream();
    byte[] chunk = new byte[8192];
    int total = 0;
    int read;

    while ((read = bodyStream.read(chunk)) != -1) {
        total += read;
        if (total > maxBytes) {
            throw new IllegalArgumentException("Body exceeds max size of " + maxBytes + " bytes");
        }
        buffer.write(chunk, 0, read);
    }

    CharBuffer decoded = StandardCharsets.UTF_8
            .newDecoder()
            .onMalformedInput(CodingErrorAction.REPORT)
            .onUnmappableCharacter(CodingErrorAction.REPORT)
            .decode(ByteBuffer.wrap(buffer.toByteArray()));

    return decoded.toString();
}
```

