```go
package service

import (
	"encoding/json"
	"fmt"
)

type Request struct {
	UserID string   `json:"user_id"`
	Action string   `json:"action"`
	Items  []string `json:"items"`
	Meta   Meta     `json:"meta"`
}

type Meta struct {
	Source string `json:"source"`
	Trace  string `json:"trace"`
}

// Before: each helper reparses the same payload.
func HandleBefore(raw []byte) error {
	if err := validateUser(raw); err != nil {
		return err
	}
	if err := processAction(raw); err != nil {
		return err
	}
	if err := auditRequest(raw); err != nil {
		return err
	}
	return nil
}

func validateUser(raw []byte) error {
	var req Request
	if err := json.Unmarshal(raw, &req); err != nil {
		return err
	}
	if req.UserID == "" {
		return fmt.Errorf("missing user_id")
	}
	return nil
}

func processAction(raw []byte) error {
	var req Request
	if err := json.Unmarshal(raw, &req); err != nil {
		return err
	}
	if req.Action == "delete" && len(req.Items) == 0 {
		return fmt.Errorf("delete requires items")
	}
	return nil
}

func auditRequest(raw []byte) error {
	var req Request
	if err := json.Unmarshal(raw, &req); err != nil {
		return err
	}
	fmt.Printf("audit source=%s trace=%s\n", req.Meta.Source, req.Meta.Trace)
	return nil
}

// After: unmarshal once, pass structured data through helpers.
func Handle(raw []byte) error {
	var req Request
	if err := json.Unmarshal(raw, &req); err != nil {
		return err
	}

	if err := validateUserReq(&req); err != nil {
		return err
	}
	if err := processActionReq(&req); err != nil {
		return err
	}
	if err := auditRequestReq(&req); err != nil {
		return err
	}
	return nil
}

func validateUserReq(req *Request) error {
	if req.UserID == "" {
		return fmt.Errorf("missing user_id")
	}
	return nil
}

func processActionReq(req *Request) error {
	if req.Action == "delete" && len(req.Items) == 0 {
		return fmt.Errorf("delete requires items")
	}
	return nil
}

func auditRequestReq(req *Request) error {
	fmt.Printf("audit source=%s trace=%s\n", req.Meta.Source, req.Meta.Trace)
	return nil
}
``` 

**Bottleneck**
- The bottleneck is repeated `json.Unmarshal(raw, &req)` across helper functions within the same request path.
- JSON unmarshalling is CPU- and allocation-heavy, so doing it 3+ times per request wastes work and increases GC pressure.

**Complexity**
Let `n` = payload size, `k` = number of helpers that re-unmarshal.

**Before**
- Time: `O(k*n)`
- Space: `O(n)` per unmarshal, repeated `k` times over the request lifecycle; transient allocation churn is much higher.

**After**
- Time: `O(n + k)`
  - `O(n)` for one unmarshal
  - `O(k)` for helpers doing field checks/business logic
- Space: `O(n)` once, plus negligible helper overhead

**Why this helps**
- Eliminates duplicate parsing
- Reduces allocations and GC churn
- Makes helpers easier to test because they operate on typed input instead of raw JSON

